        ENJOY_EXTRA_SPACE_TO_STORE_YOUR_SUNDRIES                                = 6709,  -- Enjoy extra space to store your sundries!
        REMODEL_YOUR_ROOM_TO_FIT_YOUR_FINICKY_TASTES                            = 6710,  -- Remodel your room to fit your finicky tastes!
        INCORPORATE_OSTENTATIOUS_OVERSEAS_OBJECTS_ALL_THIS_AND_MORE             = 6711,  -- Incorporate ostentatious overseas objects! All this and more!
        BUT_ONLY_ON_THE_SECOND_FLOOR_KUPO_I                                     = 6712,  -- But only on the second floor, kupo. I like the first floor as it is.
        AND_AS_FOR_YOUR_POTTED_PLANTS_THEY_ONLY                                 = 6713,  -- And as for your potted plants--they only persevere on the ground, kupo.
        AND_MOGHANCEMENT_EFFECTS_ONLY_ACTIVATE_FOR_FURNISHINGS_FITTED           = 6714,  -- And moghancement effects only activate for furnishings fitted to the first floor.
        WISH_WE_COULD_HELP_MORE_BUT_WE_SPEND                                    = 6715,  -- Wish we could help more, but we spend enormous amounts of energy on one floor already!
        GO_FORTH_AND_FROLIC_IN_YOUR_NEW_ABODE                                   = 6716,  -- Go forth and frolic in your new abode, kupo!
        YOU_CAN_ACCESS_THE_ANTECHAMBERS_FROM_THE_FRONT                          = 6717,  -- You can access the antechambers from the front door. Enjoy!
        MIGHT_BRING_A_CERTAIN_JE_NE_SAIS_QUOI                                   = 6718,  -- % might bring a certain je ne sais quoi to your Mog House, kupo!
        AH_I_NEVER_THOUGHT_THAT_THIS_DAY_WOULD                                  = 6719,  -- Ah, I never thought that this day would come, kupo...
        INDEED_IT_SEEMS_LIKE_JUST_YESTERDAY_THAT_WE                             = 6720,  -- Indeed, it seems like just yesterday that we first met here.
        I_HAVE_WATCHED_WITH_WONDER_AS_YOU_GREW                                  = 6721,  -- I have watched with wonder as you grew before my very eyes, kupo.
        IN_FACT_I_HEARD_MANY_TALES_OF_YOUR                                      = 6722,  -- In fact, I heard many tales of your boundless bravery from my friends across the world.
        EVERY_TIME_IT_MADE_ME_FEEL_MUCH_LIKE                                    = 6723,  -- Every time, it made me feel much like a proud parent would.
        IT_WAS_LIKE_I_WAS_RIGHT_THERE_WITH                                      = 6724,  -- It was like I was right there with you, kupo.
        THAT_IS_WHY_I_CEASELESSLY_CLEANED_YOUR_MOG                              = 6725,  -- That is why I ceaselessly cleaned your Mog House, merrily managed your belongings, and watered your plants.
        I_COULDN_T_REALLY_THINK_OF_ANY_OTHER                                    = 6726,  -- I couldn't really think of any other ways to help you, kupo.
        HOWEVER_I_HEARD_ABOUT_THE_TRIALS_AND_TRIBULATIONS                       = 6727,  -- However, I heard about the trials and tribulations that you've been through.
        VALHALLA_THE_MAELSTROM_MAGE_CHAOS                                       = 6728,  -- Valhalla, the Maelstrom Mage, Chaos...
        KUPOPOPO_NOW_I_CAN_ACTUALLY_ASSIST_YOU                                  = 6729,  -- Kupopopo! Now I can actually assist you!
        IT_IS_TIME_FOR_US_TO_JOYFULLY_JOIN                                      = 6730,  -- It is time for us to joyfully join forces, kupo!
        WE_CAN_DISCUSS_DETAILS_AT_THE_STONE_CIRCLE                              = 6731,  -- We can discuss details at the stone circle in the La Theine Plateau! I'll be waiting for you there, kupo!
        YOU_GO_ON_AHEAD_AND_WE_LL_SEE                                           = 6732,  -- You go on ahead, and we'll see each other soon!
