        YOU_NEED_GIL_TO_OBTAIN_A                                                = 6736,  -- You need # gil to obtain a [World Pass/Gold World Pass].
        WE_CAN_ISSUE_YOU_A_GOLD_WORLD_PASS                                      = 6737,  -- We can issue you a Gold World Pass, which bestows special benefits and can be used to invite friends to play in the same world as you are in now. How may we help you today?
        HOW_MAY_WE_HELP_YOU_I_M_FINE                                            = 6738,  -- How may we help you? I'm fine right now, thanks. Purchase a World Pass. Purchase a Gold World Pass. Tell me about Gold World Passes. Gold World Pass benefits.
        YOUR_WORLD_PASS_IS_NUMBER_OF_USES_LEFT                                  = 6739,  -- Your World Pass is: % Number of uses left: # Pass becomes invalid in: # [hour/hours] (Earth time)
        PURCHASE_A_YES_NO                                                       = 6740,  -- Purchase a [World Pass/Gold World Pass]? Yes. No.
        WHEN_USING_A_GOLD_WORLD_PASS_TO_INVITE                                  = 6741,  -- When using a Gold World Pass to invite a friend to this world, both you and your friend will be eligible for special benefits.
        A_GOLD_WORLD_PASS_CANNOT_BE_USED_IF                                     = 6742,  -- A Gold World Pass cannot be used if your account has more than one character.
        A_GOLD_WORLD_PASS_CAN_BE_USED_TO                                        = 6743,  -- A Gold World Pass can be used to invite one person per pass. As with the standard World Pass, a new pass cannot be issued until the current pass expires.
        BOTH_THE_INVITER_AND_THE_INVITEE_WILL_BE                                = 6744,  -- Both the inviter and the invitee will be eligible to receive special items; the invitee five times (once immediately following the generation of a character using the Gold World Pass, followed by 40 days, 70 days, 100 days, and 365 days subsequent to that date) and the inviter four times (the same occasions as the invitee, excluding the time of initial character generation).
        SPECIAL_ITEMS_CAN_BE_RECEIVED_BY_FORMING_A                              = 6745,  -- Special items can be received by forming a two-person party that includes the inviting and invited character, then choosing the option Gold World Pass benefits.
        IT_IS_POSSIBLE_TO_PUT_SPECIAL_ITEMS_ON                                  = 6746,  -- It is possible to put special items on hold to be received at a later date. However, please be aware that the following sequence of actions will render you unable to receive your gift.
        ID_1_THE_INVITEE_ACCEPTS_THE_ITEM_BUT_YOU                               = 6747,  -- (1) The invitee accepts the item, but you do not. (2) You claim an item for the same anniversary, but with a different invitee.
        THERE_IS_NO_LIMIT_TO_THE_NUMBER_OF                                      = 6748,  -- There is no limit to the number of Gold World Passes that can be issued to a person, but please be aware that a character can only receive special items from up to fifteen invites.
        PLEASE_CHOOSE_THIS_OPTION_AFTER_FORMING_A_TWO                           = 6749,  -- Please choose this option after forming a two-person party that includes the inviting and invited character.
        PLEASE_RETURN_FOR_YOUR_SPECIAL_ITEMS_IN_EARTH                           = 6750,  -- Please return for your special items in # [day/days] (Earth time).
        YOU_HAVE_ALREADY_ACCOMPANIED_TO_RECEIVE_YOUR_DAY                        = 6751,  -- You have already accompanied # [person/people] to receive your [1st/40th/70th/100th/365th]-day special item.
        YOU_HAVE_ALREADY_ACCOMPANIED_THIS_PERSON_TO_RECEIVE                     = 6752,  -- You have already accompanied this person to receive your [1st/40th/70th/100th/365th]-day special item.
        YOUR_FRIEND_HAS_NOT_YET_RECEIVED_A_SPECIAL                              = 6753,  -- Your friend has not yet received a special item. Please wait for your friend to receive an item first.
        IT_IS_TIME_TO_RECEIVE_YOUR_DAY_SPECIAL                                  = 6754,  -- It is time to receive your [1st/40th/70th/100th/365th]-day special item.
        YOU_ARE_ELIGIBLE_TO_SELECT_A_DAY_SPECIAL                                = 6755,  -- You are eligible to select a [1st/40th/70th/100th/365th]-day special item. Please choose from the list below.
        IF_YOU_CHOOSE_TO_RECEIVE_YOUR_ITEM_PLEASE                               = 6756,  -- If you choose to receive your item, please check whether or not your friend has done the same.
        PLEASE_BE_SURE_TO_COLLECT_YOUR_ITEM_BEFORE                              = 6757,  -- Please be sure to collect your item before claiming another with a different person for the same anniversary. Failure to do so will cause the unclaimed item to be lost forever.
        WHICH_ITEM_DO_YOU_CHOOSE_LET_ME_THINK                                   = 6758,  -- Which item do you choose? Let me think about it. %. %. %. %. %. %. %. Special item list I. Special item list II.
        WHICH_ITEM_DO_YOU_CHOOSE_LET_ME_THINK_2                                 = 6759,  -- Which item do you choose? Let me think about it. % (set of 12). %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. Choose a different item.
        YOUR_PARTY_MAKEUP_HAS_CHANGED_SO_YOU_WERE                               = 6760,  -- Your party makeup has changed so you were unable to receive the item. Please try again.
        HERE_IS_YOUR_SPECIAL_ITEM                                               = 6761,  -- Here is your special item.
        ACCEPT_THE_ITEM_YES_NO                                                  = 6762,  -- Accept the item? Yes. No.
        GOOD_LUCK_I_WILL_BESTOW_UPON_YOU_YOUR                                   = 6763,  -- Good luck, [citizen/comrade]. I will bestow upon you your nation's Signet.
        I_CANNOT_HELP_YOU_YOU_SHOULD_GO_FIND                                    = 6764,  -- I cannot help you. You should go find a guard from your own country.
        I_CANNOT_ACCEPT_CRYSTALS_FROM_SOMEONE_WHOSE_RANK                        = 6765,  -- I cannot accept crystals from someone whose rank is still 1. I advise you to either keep them until your reach rank 2, or to use them in craftwork.
        SINCE_WE_ARE_ALLIED_WITH_SAN_D_ORIA                                     = 6766,  -- Since we are allied with San d'Oria...
        SINCE_WE_ARE_ALLIED_WITH_BASTOK                                         = 6767,  -- Since we are allied with Bastok...
        SINCE_WE_ARE_ALLIED_WITH_WINDURST                                       = 6768,  -- Since we are allied with Windurst...
        I_AM_SORRY_I_AM_TOO_BUSY_WITH                                           = 6769,  -- I am sorry. I am too busy with other matters to be speaking with you.
        AH_YOU_HAVE_BROUGHT_US_SUPPLIES_THESE_WILL                              = 6770,  -- Ah, you have brought us supplies. These will help us indeed. I thank you.
        HMM_THESE_SUPPLIES_YOU_HAVE_BROUGHT_US_ARE                              = 6771,  -- Hmm... These supplies you have brought us are too old to be of any use. We will dispose of them promptly. I do commend you for your effort. May you succeed next time.
        YOU_VE_EARNED_CONQUEST_POINTS                                           = 6772,  -- You've earned conquest points!
        YOU_VE_RECEIVED_YOUR_NATION_S_SIGNET_YOU                                = 6773,  -- You've received your nation's Signet. You are now taking part in your nation's conquest campaign!
        I_AM_A_TEMPLE_KNIGHT_I_AM_ONE                                           = 6774,  -- I am , a Temple Knight. I am one of the guards charged with overseeing San d'Oria's conquest campaign.
        I_AM_AN_IRON_MUSKETEER_I_AM_ONE                                         = 6775,  -- I am , an Iron Musketeer. I am one of the guards charged with overseeing Bastok's conquest campaign.
        I_AM_A_WAR_WARLOCK_I_AM_ONE                                             = 6776,  -- I am , a War Warlock. I am one of the guards charged with overseeing Windurst's conquest campaign.
        WHAT_IS_YOUR_BUSINESS_WOULD_YOU_CAST_SIGNET                             = 6777,  -- What is your business? Would you cast Signet on me? I want to spend my conquest points. [I want to join the Expeditionary Force./Teleport me to the E.F. area.] I want to quit the E.F./change my E.F. I want to go on a supplies quest. I have some questions... Nothing, sorry to bother you.
        WHAT_DO_YOU_WISH_TO_KNOW_ABOUT_NOTHING                                  = 6778,  -- What do you wish to know about? Nothing. Conquests. Conquest results. Donating crystals. Conquest points. The effects of controlling regions. Regions controlled by other nations. Regions under beastman control.
        ALL_THREE_NATIONS_ARE_STRIVING_DAILY_TO_PUT                             = 6779,  -- All three nations are striving daily to put more regions under their control. This is what we call conquests. You can take part in it and serve your country by defeating enemies while you have Signet cast on you.
        EACH_REGION_COMPRISES_SEVERAL_AREAS_AND_THE_NATION                      = 6780,  -- Each region comprises several areas, and the nation that rids those areas of the most monsters gains control of the region.
        NATIONS_RECEIVE_GOODS_AND_RESOURCES_FROM_REGIONS_UNDER                  = 6781,  -- Nations receive goods and resources from regions under their control.
        SO_THE_MORE_REGIONS_WE_CONTROL_THE_RICHER                               = 6782,  -- So, the more regions we control, the richer our nation becomes.
        BORDER_GUARDS_ARE_ALSO_PLACED_IN_OUTPOSTS_WITHIN                        = 6783,  -- Border guards are also placed in outposts within regions under our control. They are there to cast Signet on adventurers like yourself.
        ONCE_YOU_HAVE_YOUR_NATION_S_SIGNET_YOU                                  = 6784,  -- Once you have your nation's Signet, you will be able to acquire crystals from enemies you defeat.
        NOT_ONLY_THAT_BUT_YOU_WILL_ALSO_RECEIVE                                 = 6785,  -- Not only that, but you will also receive conquest points. You get more conquest points if you defeat enemies in regions that are not under your nation's control. These points can be used to purchase items from guards like myself.
        SO_YOU_SEE_CONQUESTS_BENEFIT_NATIONS_AND_ADVENTURERS                    = 6786,  -- So you see...conquests benefit nations and adventurers alike. We expect you to do your best to serve your country.
        YOU_CAN_SEE_THE_CURRENT_STATE_OF_CONQUESTS                              = 6787,  -- You can see the current state of conquests by selecting Region Info from the main menu. Conquest results in all regions are regularly recalculated, so you may want to check them from time to time.
        SHOPS_IN_OUR_CITY_WILL_BE_SELLING_DIFFERENT                             = 6788,  -- Shops in our city will be selling different items according to our conquest rank. The Troupe Valeriano will also visit the nation that finishes first and bring a little joy to its citizens.
        YOU_CAN_DONATE_CRYSTALS_TO_YOUR_NATION_ONCE                             = 6789,  -- You can donate crystals to your nation once you achieve rank 2. Just trade them to guards like myself, and we will ensure they are sent to the proper place.
        WE_WOULD_LIKE_YOU_TO_DONATE_CRYSTALS_TO                                 = 6790,  -- We would like you to donate crystals to your nation from now on. Just trade them to guards like myself, and we will ensure they are sent to the proper place.
        YOU_CAN_ACQUIRE_CRYSTALS_BY_DEFEATING_ENEMIES_WHILE                     = 6791,  -- You can acquire crystals by defeating enemies while you have your nation's Signet. Having Signet cast on you is also the only way of taking part in conquests.
        RANK_POINTS_WILL_BE_AWARDED_TO_YOU_FOR                                  = 6792,  -- Rank points will be awarded to you for each crystal you donate, and you may be offered new missions as your rank goes up.
        YOU_ALSO_RECEIVE_RANK_POINTS_FOR_COMPLETING_MISSIONS                    = 6793,  -- You also receive rank points for completing missions. Complete missions and take part in conquests to raise your rank and serve your country.
        YOU_ARE_AWARDED_CONQUEST_POINTS_WHEN_YOU_DEFEAT                         = 6794,  -- You are awarded conquest points when you defeat monsters while you are taking part in conquests. Select "Region Info" from the menu to check your current number of conquest points.
        YOU_CAN_PURCHASE_ITEMS_FROM_GUARDS_LIKE_MYSELF                          = 6795,  -- You can purchase items from guards like myself with your conquest points, but be warned that the number of points you spend will be subtracted from your current total.
        WHEN_CONQUEST_RESULTS_ARE_ANNOUNCED_YOU_WILL_BE                         = 6796,  -- When conquest results are announced, you will be told which country controls the region you are in at that time. Sometimes regions may become neutral, or beastmen may even gain control of regions.
        IF_WE_GAIN_CONTROL_OF_A_REGION_BORDER                                   = 6797,  -- If we gain control of a region, border guards will be placed at its outposts to help adventurers like you.
        MERCHANTS_WILL_ALSO_BE_PLACED_THERE_AND_GOODS                           = 6798,  -- Merchants will also be placed there, and goods from that region will find their way to the local shops here.
        GAINING_CONTROL_OF_REGIONS_IS_THE_BASIC_PRINCIPLE                       = 6799,  -- Gaining control of regions is the basic principle behind conquests. We need each of you to do your best, and bring our nation to the top of the ranks.
        OF_COURSE_SOMETIMES_WE_LOSE_REGIONS_TO_OTHER                            = 6800,  -- Of course, sometimes we lose regions to other nations...so we must try to take them back before the next conquest results are announced.
        AS_AN_INCENTIVE_WE_WILL_AWARD_YOU_WITH                                  = 6801,  -- As an incentive, we will award you with more conquest points for defeating monsters in those regions.
        BUT_IF_WE_ARE_ALLIED_WITH_ANOTHER_NATION                                = 6802,  -- But if we are allied with another nation, you will only be awarded the regular rate for defeating monsters in our allies' regions. On the other hand, we will award you with more points for fighting in the top-ranked nation's regions.
        OUR_PARAMOUNT_CONCERN_LIES_IN_THE_BEASTMEN_GAINING                      = 6803,  -- Our paramount concern lies in the beastmen gaining control of our regions. If too many of us are defeated in a region, the beastmen will gain control of it.
        IF_THIS_HAPPENS_NOT_ONLY_IS_IT_A                                        = 6804,  -- If this happens, not only is it a great blow to our pride, but you will be unable to acquire any crystals in that region.
        THE_BEASTMEN_ARE_A_MENACE_TO_ALL_NATIONS                                = 6805,  -- The beastmen are a menace to all nations. If they rise to power, we must all unite and drive those vile creatures from that region.
        WE_NEED_YOU_TO_BRING_SUPPLIES_TO_THE                                    = 6806,  -- We need you to bring supplies to the outpost border guards who are placed in regions under our control.
        THERE_IS_ONE_OUTPOST_IN_EACH_REGION_SELECT                              = 6807,  -- There is one outpost in each region. Select Region Info from the menu, and look for the areas with a small flag mark on the map. That is where they are.
        HERE_ARE_THE_SUPPLIES_JUST_GIVE_THEM_TO                                 = 6808,  -- Here are the supplies. Just give them to the guard at the outpost and your mission will be complete. Now, choose which outpost you want to go to. We give different rewards for each region, so choose carefully.
        WHERE_DO_YOU_WISH_TO_TAKE_THE_SUPPLIES                                  = 6809,  -- Where do you wish to take the supplies? @ @ @ @ @ The Ronfaure Region.[/ (Done)] The Zulkheim Region.[/ (Done)] The Norvallen Region.[/ (Done)] The Gustaberg Region.[/ (Done)] The Derfland Region.[/ (Done)] The Sarutabaruta Region.[/ (Done)] The Kolshushu Region.[/ (Done)] The Aragoneu Region.[/ (Done)] The Fauregandi Region.[/ (Done)] The Valdeaunia Region.[/ (Done)] Qufim Island.[/ (Done)] The Li'Telor Region.[/ (Done)] The Kuzotz Region.[/ (Done)] The Vollbow Region.[/ (Done)] The Elshimo Lowlands Region.[/ (Done)] The Elshimo Uplands Region.[/ (Done)] Tu'Lia.[/ (Done)] @ The Tavnazian Archipelago.[/ (Done)] @ @ @ @ @ @ @ Cancel.
        WHICH_E_F_WOULD_YOU_LIKE_TO_JOIN                                        = 6810,  -- Which E.F. would you like to join? . . . . . . The Zulkheim Region (Lv.20`). The Norvallen Region (Lv.25`). . The Derfland Region (Lv.25`). . The Kolshushu Region (Lv.20`). The Aragoneu Region (Lv.25`). The Fauregandi Region (Lv.35`). The Valdeaunia Region (Lv.40`). The Qufim Region (Lv.25`). The Li'Telor Region (Lv.35`). The Kuzotz Region (Lv.40`). The Vollbow Region (Lv.65`). The Elshimo Lowlands Region (Lv.35`). The Elshimo Uplands Region (Lv.45`). . . . . . . . . . . None.
        SO_BE_IT_YOU_HAVE_UNTIL_THE_NEXT                                        = 6811,  -- So be it. You have until the next conquest results announcement to complete this mission. Good luck.
        WE_WILL_DISPOSE_OF_THOSE_UNUSABLE_SUPPLIES                              = 6812,  -- We will dispose of those unusable supplies.
        YOU_CAN_ONLY_UNDERTAKE_ONE_SUPPLY_MISSION_PER                           = 6813,  -- You can only undertake one supply mission per day. Come back later.
        I_AM_SORRY_WE_SEEM_TO_HAVE_A                                            = 6814,  -- I am sorry. We seem to have a problem. Let me cancel it.
        YOU_DO_NOT_NEED_TO_DONATE_ANY_MORE                                      = 6815,  -- You do not need to donate any more crystals at your current rank. Speak to the guard at the gatehouse for further instructions.
        YOUR_RANK_POINTS_ARE_FULL_WE_VE_ADDED                                   = 6816,  -- Your rank points are full. We've added the excess to your conquest points. You do not need to donate any more crystals. Go to the gatehouse for further instructions.
