        HEH_HEH_HEH_DON_T_TELL_ANYONE_BUT                                       = 7913,  -- Heh-heh-heh... Don't tell anyone, but I found me a wallet! I'm lucky, I tell you, real lucky!
        FINDERS_KEEPERS_FINDERS_KEEPERS_WONDER_WHAT_S_INSIDE                    = 7914,  -- Finders keepers, finders keepers. Wonder what's inside! Nah, I'll look later.
        WHAT_HAVE_I_GOT_HERE_LOOK_I_CAN                                         = 7915,  -- What have I got here? Look, I can't read, but I takes what I gets, and you ain't getting it back!
        SORRY_BUT_WE_RE_CURRENTLY_UNABLE_TO_ISSUE                               = 7916,  -- Sorry, but we're currently unable to issue World Passes.
