        ONCE_PUT_UP_FOR_AUCTION_MERCHANDISE_WILL_REMAIN                         = 8184,  -- Once put up for auction, merchandise will remain there for a maximum of thirty weeks Vana'diel time (nine-and-a-half days Earth time).
