        YOU_WILL_NEVER_BE_ABLE_TO_SEE_YOUR                                      = 8938,  -- You will never be able to see your chocobo again. Is that okay with you?
        UNDERSTOOD_CARE_OF_YOUR_CHOCOBO_WILL_TRANSFER_TO                        = 8939,  -- Understood. Care of your chocobo will transfer to the stables. Do you have any last words?
        WHAT_WOULD_YOU_LIKE_TO_SAY_NOTHING_I                                    = 8940,  -- What would you like to say? Nothing. I'm sorry. It's just an animal! We weren't compatible. Take good care of it.
        IS_THAT_SO_I_GUESS_THIS_IS_HARD                                         = 8941,  -- Is that so? I guess this is hard on you too, then. Sorry...
        IS_THAT_SO_THAT_S_A_GOOD_ATTITUDE                                       = 8942,  -- Is that so? That's a good attitude to have...
        I_M_DISAPPOINTED_IN_YOU                                                 = 8943,  -- ... I'm disappointed in you.
        I_DON_T_THINK_IT_S_A_MATTER                                             = 8944,  -- I don't think it's a matter of compatibility. A chocobo is not a toy!
        WE_WILL_I_M_SURE_YOU_HAVE_YOUR                                          = 8945,  -- We will. I'm sure you have your reasons, but it's still no excuse.
        OF_COURSE_NOT_WHEW_YOU_HAD_ME_FRIGHTENED                                = 8946,  -- Of course not! Whew, you had me frightened for a second there! Don't say such things!
        YOU_REALLY_WANT_TO_RETIRE_YOUR_CHOCOBO                                  = 8947,  -- You really want to retire your chocobo?
        RETIRE_YOUR_CHOCOBO_YES_NOT_YET                                         = 8948,  -- Retire your chocobo? Yes. Not yet!
        ONCE_YOU_RETIRE_YOUR_CHOCOBO_YOU_WON_T                                  = 8949,  -- Once you retire your chocobo, you won't be able to meet it anytime you want anymore. Are you okay with that?
        UNDERSTOOD_WE_HOPE_YOU_ENJOYED_RAISING_YOUR_CHOCOBO                     = 8950,  -- Understood. We hope you enjoyed raising your chocobo.
        OF_COURSE_NOT_SUCH_A_DECISION_CANNOT_BE                                 = 8951,  -- Of course not! Such a decision cannot be made in haste!
        YOUR_CHOCOBO_LEARNS_GALLOP                                              = 8952,  -- Your chocobo learns Gallop!
        YOUR_CHOCOBO_LEARNS_CANTER                                              = 8953,  -- Your chocobo learns Canter!
        YOUR_CHOCOBO_LEARNS_BURROW                                              = 8954,  -- Your chocobo learns Burrow!
        YOUR_CHOCOBO_LEARNS_BORE                                                = 8955,  -- Your chocobo learns Bore!
        YOUR_CHOCOBO_LEARNS_AUTO_REGEN                                          = 8956,  -- Your chocobo learns Auto-Regen!
        YOUR_CHOCOBO_LEARNS_TREASURE_FINDER                                     = 8957,  -- Your chocobo learns Treasure Finder!
        I_M_AFRAID_WE_STILL_AREN_T_FINISHED                                     = 8958,  -- I'm afraid we still aren't finished using the %, so I will have to return your item to you.
        YOU_GIVE_THE_TO_THE_CHOCOBO                                             = 8959,  -- You give the % to the chocobo.
        THE_CHOCOBO_LOOKS_LIKE_IT_S_ALREADY_FULL                                = 8960,  -- The chocobo looks like it's already full, but it's forcing itself to eat...
        YOUR_CHOCOBO_IS_SLEEPING_SOUNDLY_YOU_CANNOT_FEED                        = 8961,  -- Your chocobo is sleeping soundly. You cannot feed it now.
        YOUR_CHOCOBO_HAS_RUN_AWAY_YOU_CANNOT_FEED                               = 8962,  -- Your chocobo has run away. You cannot feed it now.
        YOU_CANNOT_FEED_A_CHOCOBO_THAT_HAS_NOT                                  = 8963,  -- You cannot feed a chocobo that has not hatched yet.
        IT_SEEMS_LIKE_IT_WILL_HAVE_SOME_SORT                                    = 8964,  -- It seems like it will have some sort of effect on the chocobo...
        LET_ME_KNOW_IF_YOU_HAVE_ANY_QUESTIONS                                   = 8965,  -- Let me know if you have any questions about chocobo raising.
        WHAT_WOULD_YOU_LIKE_TO_ASK_ABOUT_THE                                    = 8966,  -- What would you like to ask about? The Vana'diel Chocobo Society. Time required. Chocobo attributes. Care schedule. Caring for your chocobo. Feed. Abilities and personality. Retirement. Matchmaking. Calling chocobos in the field. Items. Chocobo digging. Summoned chocobo digging. Skill checking. Lost chicks. Nothing.
        JUST_LET_ME_KNOW_IF_YOU_EVER_GET                                        = 8967,  -- Just let me know if you ever get curious!
        THE_VANA_DIEL_CHOCOBO_SOCIETY_OR_VCS_FOR                                = 8968,  -- The Vana'diel Chocobo Society, or VCS for short, is an international organization designed to train and dispatch chocogirls and chocoguys to stables across Vana'diel.
        THEY_PROVIDE_COURSES_ON_PRACTICAL_CHOCOBO_RIDING_AND                    = 8969,  -- They provide courses on practical chocobo riding and the proper ways to care for a chocobo, as well as working to improve the treatment of chocobos from here to Aht Urhgan.
        ANYONE_CAN_JOIN_AS_LONG_AS_THEY_LOVE                                    = 8970,  -- Anyone can join as long as they love chocobos. The VCS will help you with anything you need.
        CHICKS_HATCH_FROM_EGGS_GROW_INTO_YOUNG_CHOCOBOS                         = 8971,  -- Chicks hatch from eggs, grow into young chocobos, and finally mature.
        THEY_GROW_MUCH_FASTER_THAN_PEOPLE_DO_USUALLY                            = 8972,  -- They grow much faster than people do. Usually it takes about 1 month (Earth time) before you can ride your chocobo.
        THE_CHOCOBO_S_TRAITS_ARE_DETERMINED_BY_THE                              = 8973,  -- The chocobo's traits are determined by the way in which you care for your animal. Without proper planning, you won't be able to raise the type of chocobo that you want.
        BUT_DON_T_WORRY_BECAUSE_YOU_HAVE_US                                     = 8974,  -- But don't worry, because you have us to help! We're all in this together!
        ASK_ABOUT_WHICH_ATTRIBUTE_STRENGTH_ENDURANCE_DISCERNMENT_RECEPTIVITY    = 8975,  -- Ask about which attribute? Strength. Endurance. Discernment. Receptivity. Energy. Affection. Satisfaction. Nothing.
        STRENGTH_IS_A_TERM_USED_TO_DESCRIBE_THE                                 = 8976,  -- Strength is a term used to describe the chocobo's leg power. The more strength a chocobo has, the faster it will be able to run. Rental chocobos have been raised with an emphasis on this attribute.
        BOTH_STRENGTH_AND_ENDURANCE_ARE_COLLECTIVELY_REFERRED_TO                = 8977,  -- Both strength and endurance are collectively referred to as Physical attributes.
        ENDURANCE_IS_A_TERM_USED_TO_DESCRIBE_THE                                = 8978,  -- Endurance is a term used to describe the chocobo's stamina. If your chocobo has high endurance, you will be able to ride it for a long period of time.
        BOTH_STRENGTH_AND_ENDURANCE_ARE_COLLECTIVELY_REFERRED_TO_2              = 8979,  -- Both strength and endurance are collectively referred to as Physical attributes.
        DISCERNMENT_IS_A_MUST_FOR_ANYONE_WHO_WANTS                              = 8980,  -- Discernment is a must for anyone who wants their chocobo to learn new abilities. You may want to consider raising this attribute if you are interested in digging for treasure.
        BOTH_DISCERNMENT_AND_RECEPTIVITY_ARE_COLLECTIVELY_REFERRED_TO           = 8981,  -- Both discernment and receptivity are collectively referred to as Mental attributes.
        RECEPTIVITY_IS_A_TERM_USED_TO_DESCRIBE_THE                              = 8982,  -- Receptivity is a term used to describe the chocobo's sensitivity when dealing with others. You can foster receptivity in your chocobo by giving it lots of opportunities to communicate with other chocobos.
        BOTH_DISCERNMENT_AND_RECEPTIVITY_ARE_COLLECTIVELY_REFERRED_TO_2         = 8983,  -- Both discernment and receptivity are collectively referred to as Mental attributes.
        ENERGY_IS_A_TERM_USED_TO_DESCRIBE_THE                                   = 8984,  -- Energy is a term used to describe the amount of power the chocobo needs to stay active for the day. If your chocobo has a lot of energy, care plans are more likely to be successful and you can provide more direct care for your chocobo.
        YOU_CAN_RESTORE_YOUR_CHOCOBO_S_ENERGY_BY                                = 8985,  -- You can restore your chocobo's energy by feeding it, so remember not to skip out on feeding time after a demanding schedule!
        AFFECTION_IS_THE_MOST_IMPORTANT_ATTRIBUTE_OF_ALL                        = 8986,  -- Affection is the most important attribute of all. Your care schedule will fall flat if you don't show your chocobo proper affection!
        YOU_CAN_RAISE_YOUR_CHOCOBO_S_AFFECTION_BY                               = 8987,  -- You can raise your chocobo's affection by feeding it greens and caring for it on a regular basis.
        IF_YOU_REALLY_WANT_TO_RAISE_YOUR_CHOCOBO                                = 8988,  -- If you really want to raise your chocobo's affection quickly, you can give it %, but I can't recommend doing so unless absolutely necessary.
        SATISFACTION_IS_A_TERM_USED_TO_DESCRIBE_HOW                             = 8989,  -- Satisfaction is a term used to describe how full or hungry your chocobo is. If your chocobo is full, it will gain a lot of energy before the next day.
        HOWEVER_WHEN_THE_CHOCOBO_IS_VERY_HUNGRY_ITS                             = 8990,  -- However, when the chocobo is very hungry, its energy will hardly recover at all and its affection will rapidly decrease.
        WHAT_WOULD_YOU_LIKE_TO_ASK_ABOUT_WHAT                                   = 8991,  -- What would you like to ask about? What is a care schedule? Basic care. Resting. Taking a walk. Listening to music. Exercising alone. Exercising in a group. Interacting with children. Interacting with chocobos. Carrying packages. Exhibiting to the public. Delivering messages. Digging for treasure. Acting in a play. Nothing.
        A_CARE_SCHEDULE_IS_A_SERIES_OF_PLANS                                    = 8992,  -- A care schedule is a series of plans that you set up for your chocobo so that we can take care of it while you are away.
        HOW_YOU_WANT_US_TO_CARE_FOR_YOUR                                        = 8993,  -- How you want us to care for your chocobo each day is completely up to you.
        YOU_CAN_REGISTER_UP_TO_FOUR_PLANS_AT                                    = 8994,  -- You can register up to four plans at once, each for up to 7 days (Earth time).
        WHEN_YOU_COME_TO_CHECK_ON_YOUR_CHOCOBO                                  = 8995,  -- When you come to check on your chocobo, we will give you a report on the results. You should listen closely to the report and use it as reference when deciding on a new schedule.
        WITH_THE_BASIC_CARE_PLAN_WE_WILL_PROVIDE                                = 8996,  -- With the basic care plan, we will provide the minimum level of care for your chocobo. This plan is the most stable, and your chocobo will probably not experience any sudden changes.
        THE_BASIC_CARE_PLAN_IS_GOOD_FOR_THOSE                                   = 8997,  -- The basic care plan is good for those who don't want their chocobo's traits to change much or are still unsure of what kind of schedule to choose.
        YOU_CAN_SELECT_THE_BASIC_CARE_PLAN_THE                                  = 8998,  -- You can select the basic care plan the moment you start raising your chocobo.
        THE_REST_PLAN_S_NAME_SPEAKS_FOR_ITSELF                                  = 8999,  -- The rest plan's name speaks for itself. We will give your chocobo a rest in order to restore its energy and cure any status abnormalities.
        HOWEVER_YOUR_CHOCOBO_WILL_NOT_BE_ABLE_TO                                = 9000,  -- However, your chocobo will not be able to eat any food you give it during the plan, because it will be in a deep sleep.
        WE_CAN_TAKE_YOUR_CHOCOBO_FOR_A_WALK                                     = 9001,  -- We can take your chocobo for a walk in town to improve its physical attributes of strength and endurance. However, it will have a negative effect on its mental attributes of discernment and receptivity.
        LISTENING_TO_MUSIC_WILL_IMPROVE_YOUR_CHOCOBO_S                          = 9002,  -- Listening to music will improve your chocobo's mental attributes of discernment and receptivity. However, it will have a negative effect on its physical attributes of strength and endurance.
        EXERCISING_ALONE_WILL_SIGNIFICANTLY_IMPROVE_YOUR_CHOCOBO_S              = 9003,  -- Exercising alone will significantly improve your chocobo's strength. On the other hand, its mental attributes will markedly decrease.
        IF_THE_CHOCOBO_IS_STRONG_THIS_PLAN_IS                                   = 9004,  -- If the chocobo is strong, this plan is quite effective, but if the chocobo is weak, then you shouldn't push it too hard.
        EXERCISING_WITH_CHOCOBOS_WILL_BUILD_YOUR_ANIMAL_S                       = 9005,  -- Exercising with chocobos will build your animal's endurance. On the other hand, its mental attributes will decrease.
        IF_THE_CHOCOBO_HAS_HIGH_ENDURANCE_THIS_PLAN                             = 9006,  -- If the chocobo has high endurance, this plan is quite effective, but if the chocobo's endurance is low, then you shouldn't push it too hard.
        INTERACTING_WITH_CHILDREN_HELPS_YOUR_CHOCOBO_BECOME_A                   = 9007,  -- Interacting with children helps your chocobo become a more discerning creature by interacting with people.
        HOWEVER_THIS_PLAN_WILL_HAVE_A_NEGATIVE_EFFECT                           = 9008,  -- However, this plan will have a negative effect on the chocobo's physical attributes, as no strenuous exercise is involved.
        IF_THE_CHOCOBO_HAS_GOOD_DISCERNMENT_THIS_PLAN                           = 9009,  -- If the chocobo has good discernment, this plan is quite effective, but if the chocobo does not have good discernment, then you shouldn't push it too hard.
        INTERACTING_WITH_OTHER_CHOCOBOS_IN_THE_FIELD_WILL                       = 9010,  -- Interacting with other chocobos in the field will improve the chocobo's receptivity by fostering its communication skills.
        BUT_BECAUSE_THE_FOCUS_IS_ON_COMMUNICATION_AND                           = 9011,  -- But because the focus is on communication and not exercise, this plan will have a negative effect on the chocobo's physical attributes.
        IF_THE_CHOCOBO_HAS_GOOD_RECEPTIVITY_THIS_PLAN                           = 9012,  -- If the chocobo has good receptivity, this plan is quite effective, but if the chocobo does not have good receptivity, then you shouldn't push it too hard.
        YOU_CAN_CHOOSE_TO_HAVE_YOUR_CHOCOBO_HELP                                = 9013,  -- You can choose to have your chocobo help deliver packages. Not only will this improve its physical attributes, but you will even receive payment for your services!
        THE_DOWNSIDE_IS_THAT_YOUR_CHOCOBO_S_MENTAL                              = 9014,  -- The downside is that your chocobo's mental attributes, energy, and affection will decrease. You must care well for your chocobo, or you might find yourself getting cold treatment.
        YOU_CAN_CHOOSE_TO_EXHIBIT_YOUR_CHOCOBO_TO                               = 9015,  -- You can choose to exhibit your chocobo to the public, which will allow anyone visiting the chocobo stables to take a look at your animal. Being the center of attention will help improve your chocobo's mental attributes.
        THE_DOWNSIDE_IS_THAT_YOUR_CHOCOBO_S_PHYSICAL                            = 9016,  -- The downside is that your chocobo's physical attributes, energy, and affection will decrease. You must care well for your chocobo afterwards. Also, you will receive payment for this service.
        YOU_CAN_CHOOSE_TO_HAVE_YOUR_CHOCOBO_DELIVER                             = 9017,  -- You can choose to have your chocobo deliver official messages for the nation. Not only will this improve its strength, but you will even receive payment for your services!
        HOWEVER_THIS_PLAN_CONSUMES_QUITE_A_BIT_OF                               = 9018,  -- However, this plan consumes quite a bit of your chocobo's energy, so you should feed it well to make up for it.
        YOU_CAN_HAVE_YOUR_CHOCOBO_HELP_OUT_VCS                                  = 9019,  -- You can have your chocobo help out VCS finances by digging for treasure. This will also improve the chocobo's discernment.
        THE_VCS_WILL_SELL_THE_ITEM_AND_USE                                      = 9020,  -- The VCS will sell the item and use the money for the organization's benefit, but will provide you with payment for your services.
        HOWEVER_THIS_PLAN_CONSUMES_QUITE_A_BIT_OF_2                             = 9021,  -- However, this plan consumes quite a bit of your chocobo's energy, so you should feed it well to make up for it.
        YOU_CAN_CHOOSE_TO_HAVE_YOUR_CHOCOBO_ACT                                 = 9022,  -- You can choose to have your chocobo act as an extra in a play to improve its receptivity.
        YOU_WILL_RECEIVE_PAYMENT_IN_ACCORDANCE_WITH_THE                         = 9023,  -- You will receive payment in accordance with the chocobo's performance. However, this plan consumes quite a bit of your chocobo's energy, so you should feed it well to make up for it.
        WHAT_WOULD_YOU_LIKE_TO_ASK_ABOUT_A                                      = 9024,  -- What would you like to ask about? A general explanation. Watching over your chocobo. Telling a story. Scolding. Competing. Taking a walk. Nothing.
        IN_ADDITION_TO_SETTING_THE_CHOCOBO_S_SCHEDULE                           = 9025,  -- In addition to setting the chocobo's schedule, you can also care directly for your chocobo whenever you like.
        CARING_FOR_YOUR_CHOCOBO_WILL_INCREASE_ITS_AFFECTION                     = 9026,  -- Caring for your chocobo will increase its affection for you.
        ON_THE_OTHER_HAND_A_CHOCOBO_THAT_RECEIVES                               = 9027,  -- On the other hand, a chocobo that receives too much care will lose energy more rapidly when engaging in activities. If you do nothing but care for your chocobo, it will become fatigued.
        HOWEVER_NOT_CARING_ENOUGH_FOR_YOUR_CHOCOBO_WILL                         = 9028,  -- However, not caring enough for your chocobo will have a negative effect on your relationship, so it is important to find a balance.
        YOU_CAN_WATCH_OVER_YOUR_CHOCOBO_WHENEVER_YOU                            = 9029,  -- You can watch over your chocobo whenever you like.
        YOUR_FOND_GAZE_CAN_COMMUNICATE_EVEN_MORE_THAN                           = 9030,  -- Your fond gaze can communicate even more than a touch and will not have a very tiring effect on the animal.
        YOU_CAN_TELL_THE_CHOCOBO_A_STORY_YOU                                    = 9031,  -- You can tell the chocobo a story you know. This will foster the animal's sensibilities.
        I_VE_HEARD_THAT_BY_LISTENING_TO_THE                                     = 9032,  -- I've heard that by listening to the story, the chocobo might even realize it has powers it never noticed before. (I've never seen it happen before, though...)
        SOMETIMES_YOUR_CHOCOBO_MIGHT_START_ACTING_SPOILED_OR                    = 9033,  -- Sometimes your chocobo might start acting spoiled or refuse to do anything but sleep. In such times, you will need to firmly scold it.
        THIS_WILL_SHAME_THE_ANIMAL_AND_HAVE_AN                                  = 9034,  -- This will shame the animal and have an effect on its receptivity.
        COMPETING_AGAINST_OTHER_CHOCOBOS_WILL_CULTIVATE_YOUR_ANIMAL             = 9035,  -- Competing against other chocobos will cultivate your animal's ambitious spirit and is highly effective for bored chocobos.
        YOU_CAN_TAKE_YOUR_CHOCOBO_OUT_FOR_A                                     = 9036,  -- You can take your chocobo out for a walk in the field. You will be able to choose more destinations as your chocobo grows.
        I_LIKE_TO_TAKE_THE_CHOCOBO_OUT_OFTEN                                    = 9037,  -- I like to take the chocobo out often, too, but I'm sure it prefers going out with you.
        LEAVING_THE_STABLES_EVERY_ONCE_IN_A_WHILE                               = 9038,  -- Leaving the stables every once in a while allows your chocobo to experience new sights and sounds. Maybe you'll even discover something new together!
        WHAT_WOULD_YOU_LIKE_TO_KNOW_ABOUT_WHY                                   = 9039,  -- What would you like to know about? Why feeding is important. Vegetables. Wildgrasses. Carrots. Worms. Medicines. Pastes. Nothing.
        CHOCOBOS_DIGEST_FEED_QUICKLY_SO_THEY_ARE_OFTEN                          = 9040,  -- Chocobos digest feed quickly, so they are often hungry.
        HOWEVER_THEY_ALSO_RESTORE_ENERGY_AT_A_RAPID                             = 9041,  -- However, they also restore energy at a rapid pace. If you do not feed your chocobo properly, it will be unable to restore enough energy.
        THE_CHOCOBO_STABLES_WILL_PROVIDE_YOUR_CHOCOBO_WITH                      = 9042,  -- The chocobo stables will provide your chocobo with the minimum amount of feed required for the animal to survive, but you need to provide more in order to ensure its healthy growth.
        AT_THE_SAME_TIME_FEEDING_YOUR_CHOCOBO_TOO                               = 9043,  -- At the same time, feeding your chocobo too much can result in a stomachache. Remember to strike a balance with both the variety and quantity of feed you give to your animal!
        SOME_TYPES_OF_FEED_HAVE_SPECIAL_EFFECTS_SO                              = 9044,  -- Some types of feed have special effects, so it is important not to neglect your chocobo's diet if you want to raise a good chocobo.
        THERE_ARE_DIFFERENT_METHODS_OF_ACQUIRING_THESE_SPECIAL                  = 9045,  -- There are different methods of acquiring these special types of feed, so be on the lookout for them!
        JUST_TRADE_THE_FEED_TO_AN_ADVANCED_CHOCOBO                              = 9046,  -- Just trade the feed to an advanced chocobo trainer, and they will give it to your chocobo.
        THIS_IS_THE_STANDARD_VARIETY_OF_CHOCOBO_FEED                            = 9047,  -- This is the standard variety of chocobo feed, among which % are most popular.
        CHOCOBOS_ALSO_SEEM_TO_ENJOY_AND                                         = 9048,  -- Chocobos also seem to enjoy % and %.
        THESE_GREENS_ARE_THE_MOST_EFFECTIVE_IN_SATISFYING                       = 9049,  -- These greens are the most effective in satisfying a chocobo's hunger. Chocobos also enjoy the taste, which raises affection for their owner.
        WILDGRASSES_ARE_A_TYPE_OF_MEDICINAL_HERB_THEY                           = 9050,  -- Wildgrasses are a type of medicinal herb. They do not taste very good, but are highly effective at curing status abnormalities.
        FOR_EXAMPLE_WORKS_WELL_ON_WOUNDS_SO_ALTHOUGH                            = 9051,  -- %, for example, works well on wounds. So although they look similar to %, the effects are different.
        IN_ADDITION_IS_EFFECTIVE_FOR_ILLNESS_AND_FOR                            = 9052,  -- In addition, % is effective for illness, and % for a stomachache. It's a good idea to remember which herb to use in each situation.
        CARROTS_ARE_HIGH_IN_NUTRITION_AND_WILL_HAVE                             = 9053,  -- Carrots are high in nutrition, and will have an effect on the chocobo's strength and discernment.
        FOR_EXAMPLE_AFFECT_THE_CHOCOBO_S_PHYSICAL_ATTRIBUTES                    = 9054,  -- %, for example, affect the chocobo's physical attributes, and % are good for its mental attributes. % are in a category of their own.
        REMEMBER_THOUGH_THAT_THE_RESULTS_ARE_VERY_SLIGHT                        = 9055,  -- Remember, though, that the results are very slight, and keeping a good care schedule is a far more efficient way to alter your chocobo's attributes.
        USING_WORMS_AS_FEED_CAN_HAVE_A_VARIETY                                  = 9056,  -- Using worms as feed can have a variety of effects. They might look disgusting, but their effectiveness is not to be ignored!
        FOR_EXAMPLE_WILL_DRAMATICALLY_INCREASE_YOUR_CHOCOBO_S                   = 9057,  -- For example, % will dramatically increase your chocobo's affection, and % will restore its energy.
        BUT_WATCH_OUT_FOR_THE_SIDE_EFFECTS_GIVE                                 = 9058,  -- But watch out for the side effects... Give the chocobo a worm at the wrong time, and all your effort could come to nothing...
        THE_MOST_CURIOUS_OF_ALL_THE_WORMS_IS                                    = 9059,  -- The most curious of all the worms is the %. At first it may not seem to have any effect, but looks are deceiving...
        MEDICINES_CAN_CURE_A_CHOCOBO_IN_THE_BLINK                               = 9060,  -- Medicines can cure a chocobo in the blink of an eye.
        WILL_RESTORE_YOUR_CHOCOBO_S_ENERGY_IN_FULL                              = 9061,  -- % will restore your chocobo's energy in full, making it easier to care for and ensuring that the care schedule goes smoothly.
        ARE_EFFECTIVE_FOR_MOST_STATUS_ABNORMALITIES_RESTORING_INSTANT           = 9062,  -- % are effective for most status abnormalities, restoring instant health to your chocobo. Of course, you still need to continue caring for your chocobo so it can fully recover.
        A_POTION_CAN_ALSO_HELP_FILL_A_CHOCOBO                                   = 9063,  -- A potion can also help fill a chocobo's stomach, so they can be useful when you are short on feed.
        FEED_CAN_BE_GROUND_INTO_PASTE_FOR_CHICKS                                = 9064,  -- Feed can be ground into paste for chicks to eat.
        YOU_CAN_MAKE_PASTE_YOURSELF_WITH_SOME_COOKING                           = 9065,  -- You can make paste yourself with some cooking skill. If you don't have enough cooking skill yourself, then you might want to ask a friend to make some for you.
        CHICKS_CAN_ALSO_EAT_REGULAR_FEED_THOUGH                                 = 9066,  -- Chicks can also eat regular feed, though.
        WHICH_WOULD_YOU_LIKE_TO_ASK_ABOUT_ABILITIES                             = 9067,  -- Which would you like to ask about? Abilities. Temperament. Weather preferences. Nothing.
        YOUR_CHOCOBO_MAY_LEARN_USEFUL_ABILITIES_DURING_THE                      = 9068,  -- Your chocobo may learn useful abilities during the course of its life at the stables.
        FOR_EXAMPLE_AUTO_REGEN_WILL_INCREASE_THE_RATE                           = 9069,  -- For example, Auto-Regen will increase the rate at which your chocobo restores energy. Such an ability is sure to come in handy in a variety of situations.
        YOUR_CHOCOBO_LEARNS_ABILITIES_BY_LISTENING_TO_YOUR                      = 9070,  -- Your chocobo learns abilities by listening to your words, so if you know of any story that you think might interest the animal, you should tell it often.
        BUT_REMEMBER_YOUR_CHOCOBO_CAN_T_LEARN_ALL                               = 9071,  -- But remember, your chocobo can't learn all of the abilities there are. It can only learn two...or at least, that's what I read.
        THE_CHOCOBO_S_TEMPERAMENT_IS_DETERMINED_WHEN_IT                         = 9072,  -- The chocobo's temperament is determined when it is just a chick. Its temperament and attributes are somehow related, but I'm not really sure how.
        CHOCOBOS_GENERALLY_LIKE_SUNNY_DAYS_BUT_THEY_COULD                       = 9073,  -- Chocobos generally like sunny days, but they could grow to like other kinds of weather depending on how they are raised.
        CHOCOBOS_PAY_ATTENTION_TO_THE_AIR_OUTSIDE_WHEN                          = 9074,  -- Chocobos pay attention to the air outside when they go on walks, and grow to prefer that type of weather because of the memories.
        MAKE_THE_ANIMAL_S_SCHEDULE_AROUND_ITS_PREFERRED                         = 9075,  -- Make the animal's schedule around its preferred weather days, and plans are more likely to succeed. However, if the chocobo has a favored type of weather, it also dislikes certain conditions, creating a weak point to watch for.
        YOU_CAN_CHOOSE_TO_RETIRE_YOUR_CHOCOBO_AT                                = 9076,  -- You can choose to retire your chocobo at any time after it has fully matured.
        AFTER_RETIREMENT_THE_VCS_WILL_TAKE_UP_CARING                            = 9077,  -- After retirement, the VCS will take up caring for the chocobo where you left off, so you need not worry about its welfare.
        WHEN_YOUR_CHOCOBO_RETIRES_YOU_WILL_RECEIVE_BE                           = 9078,  -- When your chocobo retires, you will receive %. Be sure not to lose it.
        YOU_CAN_USE_THE_TO_REGISTER_YOUR_CHOCOBO                                = 9079,  -- You can use the % to register your chocobo to call in the field or for matchmaking purposes after retirement. All you need to do is trade it to a VCS member.
        THE_EMPTY_STALL_CREATED_AFTER_YOUR_ANIMAL_RETIRES                       = 9080,  -- The empty stall created after your animal retires can be used for raising other chocobos, so if you happen to come across another egg, you can bring it here to start all over again!
        WHEN_YOUR_CHOCOBO_IS_MATURE_ENOUGH_YOU_CAN                              = 9081,  -- When your chocobo is mature enough, you can breed it with another chocobo. If the chocobo lays an egg, the chick will inherit the traits of its parents.
        YOU_WILL_NEED_AND_IF_YOU_WANT_TO                                        = 9082,  -- You will need % and % if you want to breed your chocobo. Apparently, you also need some kind of ticket that they sell at the stables in Upper Jeuno.
        YOU_CAN_ASK_ONE_OF_THE_VCS_MEMBERS                                      = 9083,  -- You can ask one of the VCS members to issue you a chococard, or if your chocobo is already retired, just trade them %.
        I_DON_T_REALLY_KNOW_THAT_MUCH_ABOUT                                     = 9084,  -- I don't really know that much about it, but you should probably try matching your chocobo up with several different animals and seeing what the results are.
        WHEN_YOUR_CHOCOBO_IS_MATURE_ENOUGH_YOU_CAN_2                            = 9085,  -- When your chocobo is mature enough, you can call it in the field using %.
        YOU_NEED_TO_LET_A_MEMBER_OF_THE                                         = 9086,  -- You need to let a member of the VCS know which chocobo you want to respond to your call, because they must choose a saddle that fits your chocobo's attributes.
        THAT_ALSO_MEANS_THAT_WHEN_YOUR_CHOCOBO_S                                = 9087,  -- That also means that when your chocobo's attributes change or it learns a new ability, you should probably let the VCS member know, too.
        WHEN_YOU_WANT_TO_REGISTER_A_RETIRED_CHOCOBO                             = 9088,  -- When you want to register a retired chocobo to respond to your call in the field, trade % to a VCS member.
        ALSO_THE_S_POWER_WILL_GROW_WEAK_AFTER                                   = 9089,  -- Also, the %'s power will grow weak after you've used it several times.
        IF_THIS_HAPPENS_JUST_TRADE_IT_TO_A                                      = 9090,  -- If this happens, just trade it to a VCS member and they will give you a new one for a fee.
        WHAT_WOULD_YOU_LIKE_TO_ASK_ABOUT_CHOCOCARDS                             = 9091,  -- What would you like to ask about? %. Chococards. %. Nothing.
        PROVES_THAT_YOU_ARE_YOUR_CHOCOBO_S_CARETAKER                            = 9092,  -- % proves that you are your chocobo's caretaker.
        WITH_THIS_CARD_YOU_CAN_REGISTER_A_RETIRED                               = 9093,  -- With this card, you can register a retired chocobo to respond to your call in the field or get a chococard for matchmaking.
        IF_YOU_LOSE_IT_YOU_WON_T_BE                                             = 9094,  -- If you lose it, you won't be able to get another one, so keep it in a safe place!
        YOU_CAN_USE_TO_CALL_YOUR_CHOCOBO_IN                                     = 9095,  -- You can use % to call your chocobo in the field to use as a mount.
        THE_MORE_YOU_USE_IT_THE_WEAKER_IT                                       = 9096,  -- The more you use it, the weaker it will get, so eventually you will need to exchange it to a VCS member for a new one.
        ONLY_PEOPLE_WHO_HAVE_BEEN_APPROVED_BY_THE                               = 9097,  -- Only people who have been approved by the VCS President can get %, so good luck with that...
        CHOCOCARDS_ARE_DOCUMENTS_THAT_CONTAIN_ALL_THE_DETAILS                   = 9098,  -- Chococards are documents that contain all the details about a chocobo's attributes and condition. They are divided into two types--one for each gender.
        IF_YOU_TRADE_ONE_TO_THE_PERSON_WHO                                      = 9099,  -- If you trade one to the person who's in charge of matchmaking, he'll introduce your animal to another chocobo.
        CHOCOCARDS_CONTAIN_INFORMATION_ON_THE_CHOCOBO_S_ATTRIBUTES              = 9100,  -- Chococards contain information on the chocobo's attributes and condition at the time the card is issued, so be sure to get a new card before using this service or the match will be arranged based on out-of-date information.
        IF_YOU_WANT_A_CHOCOCARD_FOR_A_RETIRED                                   = 9101,  -- If you want a chococard for a retired chocobo, then you must trade % to a VCS member.
        COMMUNICATION_WITH_YOUR_CHOCOBO_IS_THE_MOST_IMPORTANT                   = 9102,  -- Communication with your chocobo is the most important part of chocobo digging.
        YOUR_CHOCOBO_WILL_BECOME_MORE_PROACTIVE_WITH_DIGGING                    = 9103,  -- Your chocobo will become more proactive with digging the more you command it to dig!
        I_CALL_THIS_WING_SKILL_WHICH_CAN_INCREASE                               = 9104,  -- I call this "wing skill," which can increase all the way up to level #!
        I_CAN_TELL_YOU_YOUR_WING_SKILL_AT                                       = 9105,  -- I can tell you your wing skill at any time, so feel free to ask.
        YOUR_SUMMONED_CHOCOBO_S_PERSONALITY_AFFECTS_CHOCOBO_DIGGING             = 9106,  -- Your summoned chocobo's personality affects chocobo digging.
        STRONGER_CHOCOBOS_CAN_EARN_MORE_CURRENCY_AND_CHOCOBOS                   = 9107,  -- Stronger chocobos can earn more currency, and chocobos with high durability can dig up more items each day (Earth time).
        SMARTER_CHOCOBOS_SOMETIMES_DON_T_NEED_TO_EAT                            = 9108,  -- Smarter chocobos sometimes don't need to eat gysahl greens, and compassionate chocobos are more likely to find rare items.
        THERE_ARE_ALSO_A_VARIETY_OF_ABILITIES_YOUR                              = 9109,  -- There are also a variety of abilities your chocobos can learn to dig up multiple items at the same time.
