        TO_REGISTER_YOUR_CHOCOBO_YOU_MUST_FIRST_BRING                           = 10278,  -- To register your chocobo, you must first bring me either % or %.
        YOU_CAN_ONLY_REGISTER_ONE_CHOCOBO_AT_A                                  = 10279,  -- You can only register one chocobo at a time, but you may always register a new one whenever you wish.
