        WITH_NEWLY_DEVELOPED_CRA_TECHNOLOGY_YOU_CAN_NOW                         = 10281,  -- With newly developed CRA technology, you can now relive the excitement of a previously cleared official race!
        YOU_MAY_PARTICIPATE_IN_THESE_RE_RUNS_AS                                 = 10282,  -- You may participate in these re-runs as many times as you wish, but just remember--the race may be the same, but the prizes for placing won't!
        RE_RUN_WHICH_RACE_NOVICE_RACE_I_NOVICE                                  = 10283,  -- Re-run which race? Novice Race I. Novice Race II. Novice Race III. Challenge Race I. International Race I. International Race II. Challenge Race II. CRA Classic. Quit. Return.
