        VERY_WELL_FRIEND_SHOULD_YOU_EVER_FIND_YOURSELF                          = 11630,  -- Very well, friend. Should you ever find yourself in need of assistance, do not hesitate to return.
        WELCOME_TO_THE_MHMU_S_PORTER_SERVICE_KUPO                               = 11631,  -- Welcome to the MHMU's porter service, kupo! Which of your burdensome belongings shall I take off your hands today?
