        WHEN_IT_COMES_TIME_TO_RETRIEVE_YOUR_ITEM                                = 11641,  -- When it comes time to retrieve your item, just trade to me a single storage slip--any slip--once again.
        I_WILL_PRESENT_YOU_WITH_A_LIST_OF                                       = 11642,  -- I will present you with a list of all the items currently in my care, and you may choose the one you wish to withdraw. Simple as that, kupo!
        WHAT_S_MORE_NO_ADDITIONAL_TRANSACTION_FEES_WILL                         = 11643,  -- What's more, no additional transaction fees will be incurred! Pretty generous of us for a change, no?
        NOW_I_BET_YOU_RE_WONDERING_WHAT_THE                                     = 11644,  -- Now I bet you're wondering what the catch is, kupo. So as not to disappoint you, there are a few!
