        REALLY_RESET_REWARDS_YES_RESET_NO                                       = 11789,  -- Really reset rewards? Yes. (Reset ##) No.
        REWARDS_HAVE_BEEN_RESET                                                 = 11790,  -- Rewards have been reset.
        WHY_HELLO_THERE_MY_TREMENDOUS_TASK_IS_TO                                = 11791,  -- Why, hello there! My tremendous task is to tabulate your precious points for the login campaign and exchange them for pleasing prizes, kupo!
        WHY_HELLO_THERE_MY_TREMENDOUS_TASK_IS_TO_2                              = 11792,  -- Why, hello there! My tremendous task is to tabulate your precious points for the [/January/February/March/April/May/June/July/August/September/October/November/December] # login campaign and exchange them for pleasing prizes, kupo!
        WHAT_CAN_I_ASSIST_YOU_WITH_PT_CHECK                                     = 11793,  -- What can I assist you with? (# pt[/s].) Check/Exchange points. Learn about the campaign. Nothing.
        IN_THIS_LOGIN_CAMPAIGN_WE_PROVIDE_YOU_WITH                              = 11794,  -- In this login campaign, we provide you with points just for logging in once each day (Earth time), kupo!
        YOU_CAN_TRADE_THEM_FOR_INCREDIBLE_ITEMS_TO                              = 11795,  -- You can trade them for incredible items to assist you with your adventures!
        YOU_CAN_EVEN_PROCURE_MORE_POINTS_BY_LOGGING                             = 11796,  -- You can even procure more points by logging in routinely, which we all want, since Vana'diel always anxiously awaits your appearance!
        YOU_CAN_TRADE_IN_THESE_TOKENS_FOR_OUR                                   = 11797,  -- You can trade in these tokens for our gratuitous gifts any time during this campaign!
        EVEN_WHEN_THE_POINT_PROFFERING_PERIOD_HAS_PASSED                        = 11798,  -- Even when the point-proffering period has passed, you can still acquire these amazing items for a limited time, so don't forget about me, kupo!
        UP_TO_700_POINTS_FROM_THE_CURRENT_CAMPAIGN                              = 11799,  -- Up to 700 points from the current campaign can be carried over to the next one starting with the October 2025 login campaign!
        ANY_ADDITIONAL_POINTS_WILL_BE_SUMMARILY_SEIZED_KUPO                     = 11800,  -- Any additional points will be summarily seized, kupo!
        VIEW_WHICH_ITEM_PTS_POINT_ITEMS_PT_ITEMS                                = 11801,  -- View which item? (# pts.) #-point items. #-pt. items. #-pt. items. #-pt. items. #-pt. items. #-pt. items. #-pt. items. #-pt. items. Back.
        PT_ITEMS_PTS_BACK                                                       = 11802,  -- #-pt. items (# pts.): %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. Back.
        COSTS_POINT                                                             = 11803,  -- % costs # point[/s]. [You don't have enough points, kupo./Purchase this prize, kupo?/]
        HOW_MANY_WOULD_YOU_LIKE_KUPO                                            = 11804,  -- How many would you like, kupo?
        ALTANA_ABOVE_YOU_DO_NOT_POSSESS_THE_PREREQUISITE                        = 11805,  -- Altana above! You do not possess the prerequisite number of points!
        PROCEED_WITH_EXCHANGE_PT_YES_NO                                         = 11806,  -- Proceed with exchange? (# pt[/s].) Yes. No.
        WAIT_ONE_SHORT_SECOND_WHILE_I_GET_YOUR                                  = 11807,  -- Wait one short second while I get your goods!
        SOMETHING_WENT_WRONG_KUPO_TRY_AGAIN_LATER                               = 11808,  -- Something went wrong, kupo! Try again later.
        MOVE_TO_A_MOG_GARDEN_MOST_DEFINITELY_MAYBE                              = 11809,  -- Move to a Mog Garden? Most definitely! Maybe not.
        YOUR_RANK_MUST_BE_THREE_OR_HIGHER_OR                                    = 11810,  -- Your rank must be three or higher or you must possess % to enter a Mog Garden.
        HEIGH_HO_KUPO_I_M_THE_BOATSWAIN_FOR                                     = 11811,  -- Heigh-ho, kupo! I'm the boatswain for this darned-good dinghy, and it's my duty to divulge all the discursive details about Mog Gardens. So, what kind of cognition are you craving?
        WHAT_DO_YOU_WANT_TO_KNOW_NOTHING_WHAT                                   = 11812,  -- What do you want to know? Nothing. What Mog Gardens are. How to get to one. What Mog Garden books are available.
        WE_VE_GOT_STAGGERING_STORES_OF_THE_FOLLOWING                            = 11813,  -- We've got staggering stores of the following scholarly scripts and tantalizing tomes, kupo!
        WHICH_BOOK_WILL_YOU_BUY_NONE                                            = 11814,  -- Which book will you buy? None. %. %. %. %. %. %.
        IS_IT_KUPO_INTERESTINGLY_ENOUGH_THAT_ONE_IS                             = 11815,  -- %, is it, kupo? Interestingly enough, that one is reported to raise the rank of your [furrows/arboreal grove/mineral vein/pond dredger/coastal fishing net/monster rearing skills] to ridiculous reaches...for the small sum of # gil.
        BUY_THE_BOOK_YES_NO                                                     = 11816,  -- Buy the book? Yes. No.
        TRADING_TENDER_FOR_TREASURES_ISN_T_SHOPPING_SUBLIME                     = 11817,  -- Trading tender for treasures...isn't shopping sublime, kupo?
        DISAPPOINTINGLY_I_DOUBT_YOU_VE_THE_DISCERNMENT_TO                       = 11818,  -- Disappointingly, I doubt you've the discernment to descry the details of these documents. Exit then, and expand the extent of your experience.
        SORRY_BUT_OUR_STOCKS_OF_SUCH_SUNDRIES_ARE                               = 11819,  -- Sorry, but our stocks of such sundries are so scarce we can't sell them.
        MOG_GARDENS_ARE_LOVELY_LOCALES_THAT_LIE_LATENT                          = 11820,  -- Mog Gardens are lovely locales that lie latent in the west, on the Adoulin Islands. They're true treasure troves of taintless resources, frothing with fish, bursting with birds, and filled with forests, kupo!
        THINK_OF_IT_AS_YOUR_MOG_HOUSE_AWAY                                      = 11821,  -- Think of it as your Mog House away from home! Just like that fantastic facility, there's a wealth of wonders just waiting to well up for your disposal.
        SPREAD_YOUR_WINGS_AS_WIDE_AS_YOU_WISH                                   = 11822,  -- Spread your wings as wide as you wish without worrying about the consequences, kupo. The Green Thumb Moogle will handle the husbandry of this homestead while you're out hacking at hordes of hellions and cavorting across continents.
        IF_YOU_RE_SHIVERING_TO_SHOVE_OFF_THEN                                   = 11823,  -- If you're shivering to shove off, then shuffle aboard the Mog Dinghy over there! It may seem small and slightly slipshod, but the mysterious moogle magic we manifest upon it is magnificent enough to move you malms and malms in mere minutes.
        ONCE_YOU_ADJUST_TO_YOUR_ADOULINIAN_ASYLUM_I                             = 11824,  -- Once you adjust to your Adoulinian asylum, I'll even proffer printed publications that will make your Mog Garden more majestic. Grab your gil and get ready, kupo!
        WHILE_IT_D_BE_WICKEDLY_WONDERFUL_TO_WHISK                               = 11825,  -- While it'd be wickedly wonderful to whisk away everyone to Mog Gardens, only Certified Adventurers and pioneers are allowed entry to these excellent expanses of escape, kupo.
        CERTIFIED_ADVENTURERS_ARE_THOSE_WHO_HAVE_APPLIED_THEMSELVES             = 11826,  -- Certified Adventurers are those who have applied themselves assiduously, attaining the third mission rank in any nation.
        IT_DOESN_T_HAVE_TO_BE_HERE_AS                                           = 11827,  -- It doesn't have to be here as long as you were once appropriately accredited in times antecedent.
        IF_ADOULIN_S_BODY_POLITIC_HAS_PROPERLY_PERMITTED                        = 11828,  -- If Adoulin's body politic has properly permitted you to perform pioneering duties, however, your so-called rank can be lower than a leech's legs and you'll still be let in, kupo.
        PLEASED_TO_MEET_YOU_NEW_RECRUIT_IS_THERE                                = 11829,  -- Pleased to meet you, new recruit. Is there anything about which you wish to inquire?
        INQUIRE_ABOUT_WHAT_I_WANT_TO_FIND_SOME                                  = 11830,  -- Inquire about what? I want to find some quests! I want to try the tutorial event! Teach me about Records of Eminence! Teach me about the Trust initiative! I want a map of the area I'm in! I want maps of the whole city! How do I give items to people? How do I fight outside town? What are quests and missions? Tell me more about Southern San d'Oria! I have other questions. Nothing for now.
        I_CAN_MARK_THE_LOCATIONS_OF_IMPORTANT_PEOPLE                            = 11831,  -- I can mark the locations of important people on your map of the San d'Oria area, should you require it.
        YOU_CAN_FIND_A_MAP_PEDDLER_TAKING_REFUGE                                = 11832,  -- You can find a map peddler taking refuge in the shade of a tree to the southwest, near the gate to West Ronfaure.
        THERE_IS_AN_ELDERLY_WOMAN_NEAR_THE_FOUNTAIN                             = 11833,  -- There is an elderly woman near the fountain due south of here who will be more than happy to sell you maps.
        THERE_ARE_PEOPLE_WILLING_TO_SELL_YOU_MAPS                               = 11834,  -- There are people willing to sell you maps in both Northern and Southern San d'Oria, but the vendor in Northern San d'Oria is closer...if you are in a hurry.
        OUR_KINGDOM_HAS_PREPARED_A_SPECIAL_TOUR_OF                              = 11835,  -- Our kingdom has prepared a special tour of duty for newly enlisted troops such as you. Hopefully you make the best of it.
        TO_BEGIN_THE_JOURNEY_SIMPLY_TALK_TO_ALAUNE                              = 11836,  -- To begin the journey, simply talk to Alaune in Southern San d'Oria. She resides near the gate to West Ronfaure.
        TO_RENDEZVOUS_WITH_HER_HEAD_DIRECTLY_SOUTH_AND                          = 11837,  -- To rendezvous with her, head directly south and pass through the gate leading to Southern San d'Oria.
        TO_RENDEZVOUS_WITH_HER_ASCEND_THE_STAIRS_THAT                           = 11838,  -- To rendezvous with her, ascend the stairs that lead southwest, which should take you to Northern San d'Oria.
        ONCE_THERE_PROCEED_SOUTHWARD_UNTIL_YOU_REACH_SOUTHERN                   = 11839,  -- Once there, proceed southward until you reach Southern San d'Oria.
        I_SHALL_MARK_HER_POSITION_UPON_YOUR_MAP                                 = 11840,  -- I shall mark her position upon your map so you may locate her more easily once you are in that vicinity.
        IT_IS_POSSIBLE_TO_CHECK_WHO_HAS_BEEN                                    = 11841,  -- It is possible to check who has been marked on your map by opening the Map menu, selecting the Markers option, and then scrolling to the right.
        PERFORMING_A_WIDE_SCAN_FROM_THE_MAP_MENU                                = 11842,  -- Performing a Wide Scan from the Map menu also allows you to locate people in your vicinity, should that method prove more convenient.
        WHETHER_DECORATED_IN_BATTLE_OR_RECENTLY_ENLISTED_ALL                    = 11843,  -- Whether decorated in battle or recently enlisted, all can benefit from trying their hand at Records of Eminence. It is a simple method for participating in Vana'diel's many adventures, and bestows rewards all its own.
        OPEN_THE_MAIN_MENU_GO_RIGHT_TO_GET                                      = 11844,  -- Open the main menu, go right to get to the next screen, and select Objective List under the Quests submenu.
        SELECT_TUTORIAL_HEAD_TO_BASICS_AND_ACCEPT_THE                           = 11845,  -- Select Tutorial, head to Basics, and accept the objective First Step Forward to get started down this magnificent road.
        PERMIT_ME_TO_PROVIDE_YOU_WITH_A_HINT                                    = 11846,  -- Permit me to provide you with a hint for completing First Step Forward.
        FIND_THE_PERSON_DESIGNATED_BY_THE_OBJECTIVE_IN                          = 11847,  -- Find the person designated by the objective in Southern San d'Oria. I shall mark their location on your map.
        RECORDS_OF_EMINENCE_CONTAINS_A_PLETHORA_OF_OBJECTIVES                   = 11848,  -- Records of Eminence contains a plethora of objectives, many of which will surely fit your play style. It would behoove you to take advantage of this opportunity.
        THE_TRUST_INITIATIVE_IS_A_SPECIAL_MAGIC_REGIMEN                         = 11849,  -- The Trust initiative is a special magic regimen developed by one of the world's finest academies of magic.
        THOSE_WHO_SUCCESSFULLY_UNDERGO_TRAINING_WILL_BE_BESTOWED                = 11850,  -- Those who successfully undergo training will be bestowed with the ability to call forth powerful allies into battle.
        ONLY_ADVENTURERS_WHO_HAVE_PROVEN_THEIR_WORTH_BY                         = 11851,  -- Only adventurers who have proven their worth by achieving level five are eligible to participate. I will provide you with further information when you reach that landmark.
        GONDEBAUD_IS_THEIR_REPRESENTATIVE_AND_HE_IS_STATIONED                   = 11852,  -- Gondebaud is their representative, and he is stationed in Southern San d'Oria. I shall mark his location on your map should you desire to make further inquiries.
        IF_YOU_HARBOR_DOUBTS_ABOUT_SOMETHING_I_HAVE                             = 11853,  -- If you harbor doubts about something I have not yet touched upon, first open the main menu. From there, scroll right to the second page and select the Help Desk option.
        ONCE_YOU_HAVE_DONE_THAT_SELECT_HELP_DESK                                = 11854,  -- Once you have done that, select Help Desk again from the list of categories that appears in the new window. Finally, enter the section entitled I need help with the game controls.
        THE_ANSWER_TO_YOUR_QUESTION_LIKELY_LIES_THERE                           = 11855,  -- The answer to your question likely lies there.
        THOUGH_I_WISH_THE_SITUATION_WERE_LESS_DIRE                              = 11856,  -- Though I wish the situation were less dire, there exist many who require your aid. Do you wish to reference the materials I have gathered on them?
        INQUIRE_ABOUT_WHICH_LOCALE_NONE_SOUTHERN_SAN_D                          = 11857,  -- Inquire about which locale? None. Southern San d'Oria: # individual[/s]. Northern San d'Oria: # individual[/s]. Port San d'Oria: # individual[/s]. Chateau d'Oraguille: # individual[/s].
        THE_FOLLOWING_INDIVIDUALS_ARE_LIKELY_TO_REQUEST_YOUR                    = 11858,  -- The following individuals are likely to request your assistance if you are to speak to them.
        WHO_WILL_YOU_GO_SEE_IN_SOUTHERN_SAN                                     = 11859,  -- Who will you go see in Southern San d'Oria? No one. Glenne. Rosel. Raimbroy. Andecia. Parvipon. Legata. Amutiyaal. Atelloune. Maugie. Hanaa Punaa. Gondebaud. Balasiel. Balasiel. Hanaa Punaa. Helbort. Sobane. Norejaie. Paouala. Taumila. Hanaa Punaa. Balasiel. Femitte. Amaura. Deraquien. Sobane. Sharzalion. Balasiel. Rouva.
        WHO_WILL_YOU_GO_SEE_IN_NORTHERN_SAN                                     = 11860,  -- Who will you go see in Northern San d'Oria? No one. Miageau. Ailbeche. Abeaule. Abioleget. Secodiand. Kuu Mohzolhi. Ramua. Someone atop the tower. Pagisalis. Someone atop the tower. Olbergieut. Abeaule. Maloquedil. Someone atop the tower. Morjean. Eperdur. Eperdur. Vamorcote. Belgidiveau. Gulmama. Rondipur. Castilchat. Narcheral. Ailbeche. Ailbeche. Miaux.
        AGM_ANTRENEAU_WHO_WILL_YOU_GO_SEE_IN                                    = 11861,  -- Agm[(Antreneau) Who will you go see in Port San d'Oria? No one. Altiret. Gulemont. Fontoumant. Regine. Gallijaux. Joulet. Nogelle. Antreneau. Vounebariont. Portaure. Antreneau. Ceraulian. Eddy.
        WHO_WILL_YOU_GO_SEE_IN_CHATEAU_D                                        = 11862,  -- Who will you go see in Chateau d'Oraguille? No one. Halver. Curilla. Chalvatot. Curilla. Curilla. Someone beyond the door. Rahal. Curilla. Someone beyond the door. Someone beyond the door.
        ALLOW_ME_TO_MAKE_THINGS_EASIER_FOR_YOU                                  = 11863,  -- Allow me to make things easier for you and mark their location on your map.
        HEADING_THERE_ARE_WE_ALLOW_ME_TO_MARK                                   = 11864,  -- Heading there, are we? Allow me to mark your map so you do not lose your way.
        FINALLY_SOME_INFORMATION_TO_HELP_YOU_IN_YOUR                            = 11865,  -- FiNAllY, sOmE InFOrmAtiOn tO hELp yOu In yoUr TrAVelS.
        ONE_MORE_THING                                                          = 11866,  -- One more thing.
        I_HAVE_SAVED_A_RATHER_PARAMOUNT_DETAIL_FOR                              = 11867,  -- I have saved a rather paramount detail for last. Allow me to explain.
        THERE_S_STILL_ONE_OTHER_THING_REMAINING_TO                              = 11868,  -- There's still one other thing remaining to share with you.
        YOU_CAN_WARP_BETWEEN_PLACES_KNOWN_AS_HOME                               = 11869,  -- YoU CAn wArP BetWEen PlACes KnOwn aS HoME pOinTs. TheY ARe moST CoNveNieNT, sO maKe SuRE to ReGIsTer ThEM bY TouCHing ThE SurFaCE.
        HOME_POINTS_WILL_PROBABLY_TURN_OUT_TO_BE                                = 11870,  -- Home points will probably turn out to be among your best companions. Make sure to examine one if you find it, so you can warp between them and cover large distances fast.
        YOU_MAY_TELEPORT_BETWEEN_THESE_CRYSTALLINE_NODES_CALLED                 = 11871,  -- You may teleport between these crystalline nodes called home points for efficient travel. Be sure to examine any you stumble upon.
        THERE_S_SOME_SPECIAL_CRYSTAL_NODES_KNOWN_AS                             = 11872,  -- There's some special crystal nodes known as home points that'll undoubtedly serve you well. Don't forget to interact with all that you find, as they can help you get to far away places.
        IF_YOU_FIND_YOURSELF_IN_A_FARAWAY_PLACE                                 = 11873,  -- If yOU fINd yOurSeLF iN A fARaWay pLaCe, maKe sURe tO FinD a StoRE to BuY a Map fROm! wIth a MaP, yoU CaN ChEck WheRe yOu ArE!
        SHOULD_YOU_FIND_YOURSELF_LOST_IN_THE_MIDDLE                             = 11874,  -- Should you find yourself lost in the middle of nowhere, try to make it back to town to buy a map. That way, you can get your bearings.
        REMEMBER_TO_PURCHASE_A_MAP_FROM_THE_APPROPRIATE                         = 11875,  -- Remember to purchase a map from the appropriate vendor before going to a faraway land. If you do, you can check your location within that place.
        DID_YOU_KNOW_THAT_SOME_VENDORS_WILL_SELL                                = 11876,  -- Did you know that some vendors will sell you maps of specific areas? It sure beats stumbling around like a dullard!
        DON_T_WASTE_PRECIOUS_ITEMS_BY_SELLING_THEM                              = 11877,  -- DoN'T WaSTe pRecIOus iTemS By sEllINg tHeM tO a StoRe. MaKE eVen MoRe MonEy By PuTTing tHeM uP At tHe AucTIon HouSe!
        I_HATE_TO_SAY_IT_BUT_THE_MERCHANTS                                      = 11878,  -- I hate to say it, but the merchants around here are pretty stingy. You'd have more luck listing any unwanted goods at the auction house.
        I_ADVISE_YOU_TO_PUT_ANY_UNWANTED_GOODS                                  = 11879,  -- I advise you to put any unwanted goods up for sale at the auction house rather than be taken advantage of by the vendors here.
        IF_THERE_S_SOMETHING_YOU_VE_GOT_THAT                                    = 11880,  -- If there's something you've got that you don't need, try putting it up at the auction house rather than selling it to some unscrupulous vendor.
        MANY_UNDEAD_MONSTERS_CAN_SENSE_WHEN_YOU_ARE                             = 11881,  -- MaNY uNdEaD MOnsTeRS cAn SenSe WhEn yOU Are LoW oN HP, aNd wIll TAke tHaT opPOrtUnItY tO ComE AfTEr yOu!
        UNDEAD_ENEMIES_TEND_TO_COME_OUT_OF_THE                                  = 11882,  -- Undead enemies tend to come out of the woodwork when your HP is low. Be careful.
        THE_UNDEAD_OFTEN_ASSAULT_ADVENTURERS_WITH_LOW_HP                        = 11883,  -- The undead often assault adventurers with low HP, which is all the more reason to never let your guard down in the wilderness.
        UNDEAD_ARE_ALWAYS_OUT_FOR_BLOOD_AND_BRAINS                              = 11884,  -- Undead are always out for blood and brains, so watch out if you're low on health! They'll make a beeline right for you.
        LET_S_TALK_ABOUT_ATTRIBUTES_INCREASING_YOUR_STRENGTH                    = 11885,  -- LeT'S tALk aBouT AttRIButeS. InCReaSing yoUr StrenGTh (STR) wiLL iNcrEase YouR pHYsiCal, bUt NOt MaGiCal, AttACk.
        INCREASING_YOUR_STRENGTH_STR_RAISES_YOUR_ATTACK_POWER                   = 11886,  -- Increasing your strength (STR) raises your attack power, but--sadly--not your magic attack.
        INCREASING_YOUR_STRENGTH_STR_ENHANCES_YOUR_ATTACK_POWER                 = 11887,  -- Increasing your strength (STR) enhances your attack power, but--regrettably--does nothing for your magic attack.
        INCREASING_YOUR_STRENGTH_STR_ENHANCES_YOUR_ATTACK_POWER_2               = 11888,  -- Increasing your strength (STR) enhances your attack power, but unfortunately does nothing for the efficacy of your magic.
        LET_S_TALK_ABOUT_ATTRIBUTES_INCREASING_YOUR_DEXTERITY                   = 11889,  -- LeT'S tALk aBouT AttRIButeS. InCReaSinG yoUr DeXteRIty (DEX) wiLl IncReaSe yOuR AccURacY aNd cRiTIcaL HIt rAtE.
        INCREASING_YOUR_DEXTERITY_DEX_INCREASES_THINGS_LIKE_YOUR                = 11890,  -- Increasing your dexterity (DEX) increases things like your accuracy and critical hit rate.
        INCREASING_YOUR_DEXTERITY_DEX_IMPROVES_SUCH_FACULTIES_AS                = 11891,  -- Increasing your dexterity (DEX) improves such faculties as accuracy and critical hit rate.
        INCREASING_YOUR_DEXTERITY_DEX_ENHANCES_ATTRIBUTES_SUCH_AS               = 11892,  -- Increasing your dexterity (DEX) enhances attributes such as accuracy and critical hit rate.
        LET_S_TALK_ABOUT_ATTRIBUTES_INCREASING_YOUR_VITALITY                    = 11893,  -- LeT'S tALk aBouT AttRIButeS. InCreAsinG YoUR VitALiTy (VIT) WiLL iNcReaSE yOuR PhYsiCAl DefENsE anD HP reStoREd bY CuRe aNd oTheR HP-HeaLInG aBilItieS.
        INCREASING_YOUR_VITALITY_VIT_INCREASES_THINGS_LIKE_YOUR                 = 11894,  -- Increasing your vitality (VIT) increases things like your physical defense and the potency of restorative abilities such as Cure.
        INCREASING_YOUR_VITALITY_VIT_IMPROVES_SUCH_FACULTIES_AS                 = 11895,  -- Increasing your vitality (VIT) improves such faculties as physical defense and the potency of restorative abilities like Cure.
        INCREASING_YOUR_VITALITY_VIT_ENHANCES_ATTRIBUTES_SUCH_AS                = 11896,  -- Increasing your vitality (VIT) enhances attributes such as physical defense and restorative abilities such as cure.
        LET_S_TALK_ABOUT_ATTRIBUTES_AGILITY_AGI_HAS                             = 11897,  -- LeT'S tALk aBouT AttRIButeS. AgIlITy (AGI) hAs a VarIetY Of EffECtS, sUch aS IncReaSing pHYsIcaL EvaSioN And aCCurAcy oF RangEd aTTacKs, as WelL aS DecReasINg eNEmiES' CRitIcAL HiT EvaSioN.
        INCREASING_YOUR_AGILITY_AGI_INCREASES_THINGS_LIKE_YOUR                  = 11898,  -- Increasing your agility (AGI) increases things like your physical evasion and ranged accuracy. It also decreases enemies' critical hit evasion.
        INCREASING_YOUR_AGILITY_AGI_IMPROVES_SUCH_FACULTIES_AS                  = 11899,  -- Increasing your agility (AGI) improves such faculties as physical evasion and ranged accuracy. It also reduces enemies' critical hit evasion.
        INCREASING_YOUR_AGILITY_AGI_ENHANCES_ATTRIBUTES_SUCH_AS                 = 11900,  -- Increasing your agility (AGI) enhances attributes such as physical evasion and ranged accuracy. It also decreases enemies' critical hit evasion.
        LET_S_TALK_ABOUT_ATTRIBUTES_INTELLIGENCE_INT_INCREASES                  = 11901,  -- LeT'S tALk aBouT AttRIButeS. InTElLiGEncE (INT) iNcReaSEs tHe MagIC aCCuraCy and DaMAge Of ElEmenTAL MaGiC sPeLLs.
        INCREASING_YOUR_INTELLIGENCE_INT_INCREASES_THINGS_LIKE_THE              = 11902,  -- Increasing your intelligence (INT) increases things like the accuracy and damage of your elemental magic spells.
        INCREASING_YOUR_INTELLIGENCE_INT_IMPROVES_SUCH_FACULTIES_AS             = 11903,  -- Increasing your intelligence (INT) improves such faculties as the accuracy and damage of your elemental magic spells.
        INCREASING_YOUR_INTELLIGENCE_INT_ENHANCES_ATTRIBUTES_SUCH_AS            = 11904,  -- Increasing your intelligence (INT) enhances attributes such as the accuracy and damage of your elemental magic spells.
        LET_S_TALK_ABOUT_ATTRIBUTES_MIND_MND_INCREASES                          = 11905,  -- LeT'S tALk aBouT AttRIButeS. MiND (MND) iNCreAsEs thE aMouNT oF HP ReStoREd bY HeaLinG MaGiC and tHE ACcuraCy oF WhItE MAgiC SpELls.
        MIND_MND_INCREASES_THINGS_LIKE_THE_POTENCY_OF                           = 11906,  -- Mind (MND) increases things like the potency of healing spells and the accuracy of white magic spells.
        MIND_MND_IMPROVES_SUCH_FACULTIES_AS_THE_POTENCY                         = 11907,  -- Mind (MND) improves such faculties as the potency of healing spells and the accuracy of white magic spells.
        INCREASING_YOUR_MIND_MND_ENHANCES_ATTRIBUTES_SUCH_AS                    = 11908,  -- Increasing your mind (MND) enhances attributes such as the potency of healing spells and the accuracy of white magic spells.
        LET_S_TALK_ABOUT_ATTRIBUTES_CHARISMA_CHR_INCREASES                      = 11909,  -- LeT'S tALk aBouT AttRIButeS. cHaRIsmA (CHR) inCreASes tHe eFFecTivENesS oF a bEaSTmaSTeR's cHaRm aNd thE AccURaCy Of A BarD's sONgs.
        CHARISMA_CHR_INCREASES_THINGS_LIKE_THE_EFFECTIVENESS_OF                 = 11910,  -- Charisma (CHR) increases things like the effectiveness of the beastmaster ability charm and the accuracy of bards' songs.
        CHARISMA_CHR_IMPROVES_SUCH_FACULTIES_AS_THE_EFFECTIVENESS               = 11911,  -- Charisma (CHR) improves such faculties as the effectiveness of the beastmaster ability charm and the accuracy of bards' songs.
        INCREASING_YOUR_CHARISMA_CHR_ENHANCES_ATTRIBUTES_SUCH_AS                = 11912,  -- Increasing your charisma (CHR) enhances attributes such as the effectiveness of the beastmaster ability charm and the accuracy of bards' songs.
        LOOK_AS_LONG_AS_YOU_DESIRE_I_SHALL                                      = 11913,  -- Look as long as you desire. I shall not interfere.
        RUMOIE_IN_SOUTHERN_SAN_D_ORIA_ALSO_FANCIES                              = 11914,  -- Rumoie in Southern San d'Oria also fancies herself something of a cartographer. You can always go to her if you want your map marked.
        THE_ACTION_OF_HANDING_OVER_OBJECTS_TO_OTHERS                            = 11915,  -- The action of handing over objects to others is termed trading here. To trade items to people, open the main menu--which will appear on the right-hand side of your screen--and select Trade.
        IN_THE_EVENT_YOU_HAVE_NEGLECTED_TO_TARGET                               = 11916,  -- In the event you have neglected to target your interlocutor, please do so after selecting the Trade option. Afterwards, choose the item or items you wish to bequeath in the window that appears and hit OK.
        THIS_PROCESS_WILL_BE_AN_INTEGRAL_PART_OF                                = 11917,  -- This process will be an integral part of the quests and missions you shall undertake in the future, so I entreat you to commit it to memory.
        SHOULD_YOU_BE_IN_POSSESSION_OF_PLEASE_TRADE                             = 11918,  -- Should you be in possession of %, please trade it to me. In return, I shall bestow some monetary remunerations upon you, care of the monarchy.
        IT_WOULD_BEHOOVE_YOU_TO_REMEMBER_THE_FOLLOWING                          = 11919,  -- It would behoove you to remember the following points when engaging in combat outside the city gates. One: outfit yourself with weapons and armor. Two: magic spells are learned from scrolls.
        THIRDLY_AND_OF_THE_UTMOST_IMPORT_IS_THAT                                = 11920,  -- Thirdly--and of the utmost import--is that you check your adversaries before challenging them. It would not do for you to go charging into battle against an enemy who thoroughly outclasses you.
        FINALLY_NEVER_FORGET_TO_CHECK_YOUR_SPOILS_OF                            = 11921,  -- Finally, never forget to check your spoils of war.
        TASKS_ISSUED_BY_RESIDENTS_OF_THE_CITY_FOR                               = 11922,  -- Tasks issued by residents of the city for you to complete are called quests. Simply fulfill the requirements, such as procuring the desired item, to receive a reward.
        ON_THE_OTHER_HAND_ORDERS_HANDED_DOWN_DIRECTLY                           = 11923,  -- On the other hand, orders handed down directly from those involved with the nation's administration are called missions. Converse with the guard by the gate for a more detailed explanation.
        OPEN_THE_MAP_OPTION_FROM_THE_MAIN_MENU                                  = 11924,  -- Open the Map option from the main menu, select Markers, and then scroll to the right. That will tell you where you need to go.
        SELECTING_MAP_FROM_THE_MAIN_MENU_OPENS_THE                              = 11925,  -- Selecting Map from the main menu opens the map of the area in which you currently reside. Select Markers and press the right arrow key to see all the markers placed on your map.
        SHE_MIGHT_BE_A_TAD_MORE_CRITICAL_THAN                                   = 11926,  -- She might be a tad more critical than most, so you might want to be careful.
        OPEN_THE_MAP_OPTION_FROM_THE_MAIN_MENU_2                                = 11927,  -- Open the Map option from the main menu, select Markers, and then scroll to the right to find where she is stationed.
        BY_THE_WAY_TEILSA_IS_A_LADY_OF                                          = 11928,  -- By the way, Teilsa is a lady of traditional Elvaan upbringing, so try not to say anything that will offend her sensibilities. Anyway, let me mark her location on your map.
        NOW_YOU_CAN_CHECK_HER_POSITION_ANYTIME_BY                               = 11929,  -- Now you can check her position anytime by opening the Map option from the main menu, selecting Markers, and scrolling to the right.
        IT_MIGHT_BE_IN_YOUR_BEST_INTERESTS_TO                                   = 11930,  -- It might be in your best interests to speak to [Urbiolaine/Igsli/Teldro-Kesdrodo/Nunaarl Bthtrogg] in % [(G-10)/(E-11)/(J-10)/(H-11)].
        JOIN_WHICH_UNITY_I_NEED_TIME_TO_CONSIDER                                = 11931,  -- Join which Unity? I need time to consider. Pieuje. Ayame. Invincible Shield. Apururu. Maat. Aldo. Jakoh Wahcondalo. Naja Salaheem. Flaviria. Yoran-Oran. Sylvie.
        SHOULD_YOU_JOIN_ONE_UNITY_YOU_WILL_NOT                                  = 11932,  -- Should you join one Unity, you will not be able to switch to another one until the rankings are tallied. Proceed anyway?
        JOIN_UNITY_YES_NO                                                       = 11933,  -- Join [Pieuje's/Ayame's/Invincible Shield's/Apururu's/Maat's/Aldo's/Jakoh Wahcondalo's/Naja Salaheem's/Flaviria's/Yoran-Oran's/Sylvie's] Unity? Yes. No.
        SWITCHING_UNITIES_WILL_COST_A_TOTAL_OF_UNITY                            = 11934,  -- Switching Unities will cost a total of # Unity accolade[/s], and you will be unable to switch until the rankings are tabulated. Are you sure you wish to switch Unities?
        JOIN_UNITY_ACC_YES_COST_ACCOLADE_NO                                     = 11935,  -- Join [Pieuje's/Ayame's/Invincible Shield's/Apururu's/Maat's/Aldo's/Jakoh Wahcondalo's/Naja Salaheem's/Flaviria's/Yoran-Oran's/Sylvie's] Unity? (# acc.) Yes. (Cost: # accolade[/s]) No.
        YOU_HAVE_JOINED_UNITY                                                   = 11936,  -- You have joined [Pieuje's/Ayame's/Invincible Shield's/Apururu's/Maat's/Aldo's/Jakoh Wahcondalo's/Naja Salaheem's/Flaviria's/Yoran-Oran's/Sylvie's] Unity!
        ANY_ACTIONS_TO_TAKE_NONE_AT_THE_MOMENT                                  = 11937,  -- Any actions to take? None at the moment. Bring me to a Wanted encounter area. Enhance my equipment.[/ (In progress)] Add an attribute to enhanced equipment. Items, please. (Up to # acc.) Special mats! (Up to # acc.) I want to change Unities. Tell me more about all this.
        WHICH_AREA_RETURN_TO_PREVIOUS_SELECTION_CURRENTLY_ACCEPTED              = 11938,  -- Which area? Return to previous selection. Currently accepted area. Content level 99 and below. Content level 119. Content level 122. Content level 125. Content level 128. Content level 135. Content level 145. Content level 137.
        GO_TO_WHICH_AREA_RETURN_TO_PREVIOUS_SELECTION                           = 11939,  -- Go to which area? Return to previous selection. %. %. %. %. %. %. %. %. Next page.
        GO_TO_ACC_YES_COST_ACCOLADE_NOT_NOW                                     = 11940,  -- Go to %? (# acc.) Yes. (Cost: # accolade[/s]) Not now.
        HEAR_AN_EXPLANATION_ON_WHICH_TOPIC_RETURN_TO                            = 11941,  -- Hear an explanation on which topic? Return to previous selection. Give me a quick outline. Unity Concord. Unities. Unity chat. Connection with Records of Eminence. Wanted battles. Enhancing equipment. Adding attributes to enhanced equipment. Rewards and accolades. Changing Unities. Unity rankings. Unity leader alter egos.
        SELECT_A_TYPE_OF_EQUIPMENT_RETURN_TO_PREVIOUS                           = 11942,  -- Select a type of equipment. Return to previous selection. Item level 119 weapons/shields. Item level 119 headgear. Item level 119 chestgear. Item level 119 handgear. Item level 119 leggear. Item level 119 footgear. Level 99 equipment. Level 98 and lower equipment. Accessories.
