        SELECT_AN_ITEM_CATEGORY_RETURN_TO_PREVIOUS_SELECTION                    = 11944,  -- Select an item category. Return to previous selection. @ @ @ @
        WHICH_UP_TO_ACC_RETURN_TO_PREVIOUS_SELECTION                            = 11945,  -- Which? (Up to #) (# acc.) Return to previous selection. %: # acc. %: # acc. %: # acc. %: # acc. %: # acc. %: # acc. %: # acc. %: # acc. Next page.
        BUY_YES_PLEASE_COST_ACCOLADE_NO_THANK_YOU                               = 11946,  -- Buy %? Yes, please. (Cost: # accolade[/s]) No, thank you.
        YES_PLEASE_COST_ACCOLADE_NO_THANK_YOU                                   = 11947,  -- # ? Yes, please. (Cost: # accolade[/s]) No, thank you.
