        I_MUST_CONFESS_MY_TREPIDATION_AT_THE_CURRENT                            = 12134,  -- I must confess my trepidation at the current state of affairs. What if the darkness overcomes you not in the future, but even earlier than I had anticipated?
        WHAT_A_MORBID_STATE_OF_AFFAIRS_WE_FIND                                  = 12135,  -- What a morbid state of affairs we find ourselves in.
        WE_MUST_TAKE_SOLACE_IN_THE_HOPE_THAT                                    = 12136,  -- We must take solace in the hope that the orb will guide you to safety, so that you will be prepared for the Reckoning.
        UNTIL_THAT_TIME_YOUR_FOOTSTEPS_MUST_REMAIN_UNERRING                     = 12137,  -- Until that time, your footsteps must remain unerring.
        AND_SO_FATE_GUIDES_YOU_TO_CEIZAK_BATTLEGROUNDS                          = 12138,  -- And so fate guides you to Ceizak Battlegrounds...
        THE_FUTURE_SHOULD_HAVE_CHANGED                                          = 12139,  -- The future should have changed...
        AND_I_SHOULD_HAVE_BEEN_DISSOLVED_INTO_NOTHINGNESS                       = 12140,  -- ...And I should have been dissolved into nothingness.
        YET_THE_CRYSTAL_S_CLARION_SONG_HAS_CEASED                               = 12141,  -- Yet the crystal's clarion song has ceased.
        AND_THE_CLOUD_OF_DARKNESS_THREATENS_THE_WORLD                           = 12142,  -- And the Cloud of Darkness threatens the world once more.
        THIS_IS_AN_EXPLANATION_OF_THE_ASSIST_CHANNEL                            = 12143,  -- This is an explanation of the Assist Channel feature, which allows new and returning players to seek help from veteran adventurers.
        YOU_MUST_TAKE_ON_THE_RECORDS_OF_EMINENCE                                = 12144,  -- You must take on the % Records of Eminence objective before receiving the explanation.
        YOU_MUST_COMPLETE_BEFORE_TAKING_ON_THE_RECORDS                          = 12145,  -- You must complete % before taking on the % Records of Eminence objective.
        WHAT_DO_YOU_WANT_TO_LEARN_ABOUT_WHAT                                    = 12146,  -- What do you want to learn about? What is the Assist Channel? How can I post a message? What are the requirements? Where can I access it? Tell me about mentor messages. Where can I find mentors? What are Thumbs Up and Warnings? What happens if I am muted? When do my posting rights expire? Nothing for now.
        THE_ASSIST_CHANNEL_IS_A_SPECIAL_CHAT_CHANNEL                            = 12147,  -- The Assist Channel is a special chat channel that allows adventurers to ask questions and receive advice from veteran players known as mentors.
        PRESS_THE_SPACE_BAR_TO_BRING_UP_THE                                     = 12148,  -- Press the space bar to bring up the text window at the bottom of the screen and type /assistj (your message) or /assiste (your message) to post your message.
        YOU_CAN_ALSO_USE_AJ_FOR_ASSISTJ_AND                                     = 12149,  -- You can also use /aj for /assistj, and /ae for /assiste.
        ADDITIONALLY_PRESSING_CTRL_Q_WILL_DISPLAY_ASSISTJ_OR                    = 12150,  -- Additionally, pressing CTRL+Q will display /assistj or /assiste in the text window for you.
        YOU_CAN_CHANGE_THE_CTRL_Q_SHORTCUT_COMMAND                              = 12151,  -- You can change the CTRL+Q shortcut command...
        BY_GOING_TO_MAIN_MENU_CONFIG_MISC_2                                     = 12152,  -- ...by going to Main Menu > Config > Misc. 2 > Key Assignment > Commands > Chat: /AssistE or /AssistJ.
        IT_IS_RECOMMENDED_THAT_YOU_USE_ASSISTJ_AJ                               = 12153,  -- It is recommended that you use /assistj (/aj) when posting in Japanese, and /assiste (/ae) when posting in English.
        YOU_MUST_MEET_ONE_OF_THE_FOLLOWING_CONDITIONS                           = 12154,  -- You must meet one of the following conditions in order to post to the Assist Channel.
        ID_1_YOU_ARE_A_NEW_PLAYER_YOU_MAY                                       = 12155,  -- 1. You are a new player You may post messages from the moment you first set foot in Vana'diel.
        ID_2_YOU_ARE_A_RETURNEE_AS_A_RETURNING                                  = 12156,  -- 2. You are a returnee As a returning player, you may post messages upon logging in with a character that has not logged in for at least 48 days.
        ID_3_YOU_ARE_A_MENTOR_YOU_MAY_POST                                      = 12157,  -- 3. You are a mentor You may post messages as long as you remain a mentor to other players.
        NEW_PLAYERS_AND_RETURNEES_MAY_POST_MESSAGES_UNTIL                       = 12158,  -- New players and returnees may post messages until they have been logged in for a total of 48 hours since first receiving their posting rights.
        IF_YOU_WISH_TO_CHECK_HOW_LONG_YOU                                       = 12159,  -- If you wish to check how long you can continue to post for, speak to an and choose "When do my posting rights expire?" to see how much time you have left.
        THE_ASSIST_CHANNEL_CAN_ONLY_BE_USED_IN                                  = 12160,  -- The Assist Channel can only be used in the following areas.
        AVAILABLE_AREAS                                                         = 12161,  -- Available areas: %, %, %, %, %, %...
        ID_12162                                                                = 12162,  -- ...%, %, %, %, %, %, %, %...
        ID_12163                                                                = 12163,  -- ...%, %, %, %, %, %, %, %...
        AND_YOUR_MOG_HOUSE_RENT_A_ROOM                                          = 12164,  -- ...%, %, %, and your Mog House (Rent-a-Room).
        YOU_CANNOT_POST_OR_READ_MESSAGES_OUTSIDE_OF                             = 12165,  -- You cannot post or read messages outside of the areas listed above.
        EVEN_IN_AREAS_WHERE_MESSAGES_ARE_ALLOWED_YOU                            = 12166,  -- Even in areas where messages are allowed, you cannot post consecutive messages. Please wait a while after posting a message.
        MENTOR_MESSAGES_ARE_ACCOMPANIED_BY_A_FLAG_O                             = 12167,  -- Mentor messages are accompanied by a flag (o/) marker. This marker indicates the mentor's reliability (Mentor Class) and experience as an adventurer (Mastery Rank).
        AS_A_MENTOR_S_MENTOR_CLASS_INCREASES_THE                                = 12168,  -- As a mentor's Mentor Class increases, the color and shape of the marker will change: o/ > o9 > oC
        A_OC_MARKER_IS_A_SIGN_THAT_THE                                          = 12169,  -- A oC marker is a sign that the mentor has earned the highest levels of trust from other adventurers.
        THE_NUMBER_AFFIXED_TO_THE_MARKER_IS_THE                                 = 12170,  -- The number affixed to the marker is the mentor's Mastery Rank, and indicates how experienced the mentor is as an adventurer.
        THE_HIGHER_THE_NUMBER_THE_MORE_EXPERIENCED_THE                          = 12171,  -- The higher the number, the more experienced the mentor is.
        YOU_CAN_CHECK_YOUR_OWN_MASTERY_RANK_EVEN                                = 12172,  -- You can check your own Mastery Rank even if you do not serve as a mentor, so feel free to take a look every now and then if you are curious.
        YOU_CAN_CHECK_YOUR_MASTERY_RANK_BY_GOING                                = 12173,  -- You can check your Mastery Rank by going to Main Menu > Status > Profile.
        IF_YOU_WISH_TO_SPEAK_DIRECTLY_TO_A                                      = 12174,  -- If you wish to speak directly to a mentor, you can search for mentors by going to Main Menu > Help Desk > Mentor Search.
        THE_THUMBS_UP_FEATURE_ENABLES_YOU_TO_LET                                = 12175,  -- The Thumbs Up feature enables you to let mentors know when their comments proved to be especially helpful.
        MENTORS_WHO_EARN_LOTS_OF_THUMBS_UP_REPLIES                              = 12176,  -- Mentors who earn lots of Thumbs Up replies from other adventurers will see their Mentor Class increase.
        REMEMBER_TO_GIVE_A_THUMBS_UP_TO_ANY                                     = 12177,  -- Remember to give a Thumbs Up to any mentor you feel helped you out or taught you something useful.
        A_WARNING_IS_A_FEATURE_THAT_CAN_ONLY                                    = 12178,  -- A Warning is a feature that can only be used by mentors.
        PLEASE_USE_THIS_FEATURE_WHEN_A_POST_S                                   = 12179,  -- Please use this feature when a post's contents are insufficient or otherwise may be construed as harassment.
        TO_SEND_A_THUMBS_UP_OR_WARNING_TO                                       = 12180,  -- To send a Thumbs Up or Warning to another player, open the Chat Log Window and move the cursor over the relevant message and press the confirm button (Enter key) to bring up the evaluation menu.
        EVALUATIONS_CAN_BE_MADE_FOR_10_MINUTES_FOLLOWING                        = 12181,  -- Evaluations can be made for 10 minutes following the designated player's latest post to the Assist Channel.
        YOU_MAY_SEND_UP_TO_ONE_THUMBS_UP                                        = 12182,  -- You may send up to one Thumbs Up and one Warning per day (Earth time).
        THE_MUTE_FEATURE_PLACES_RESTRICTIONS_ON_YOUR_ABILITY                    = 12183,  -- The Mute feature places restrictions on your ability to post, meaning that other players will be unable to see the messages you post to the Assist Channel.
        PLEASE_REFRAIN_FROM_POSTING_UNSUITABLE_CONTENT_SO_THAT                  = 12184,  -- Please refrain from posting unsuitable content so that the veteran adventurers are not forced to mute you.
        MUTE_STATUS_CAN_BE_REMOVED_BY_PLAYERS_THAT                              = 12185,  -- Mute status can be removed by players that have the necessary Mute List access rights, or it will be removed automatically 24 hours (Earth time) after the mute status was enabled.
        YOU_ARE_FREE_TO_POST_MESSAGES_TO_THE                                    = 12186,  -- You are free to post messages to the Assist Channel until you decide to stop serving as a mentor.
        YOU_MAY_POST_MESSAGES_TO_THE_ASSIST_CHANNEL                             = 12187,  -- You may post messages to the Assist Channel until : on //. (Time remaining: Approx. # [sec./min./hr.])
        IF_YOU_LOG_OUT_WHILE_YOU_STILL_HAVE                                     = 12188,  -- If you log out while you still have time available, your remaining time will be carried over to the next time you log in.
        YOU_ARE_ABOUT_TO_LOSE_THE_ABILITY_TO                                    = 12189,  -- You are about to lose the ability to post messages to the Assist Channel.
        YOU_ARE_UNABLE_TO_POST_MESSAGES_TO_THE                                  = 12190,  -- You are unable to post messages to the Assist Channel.
        TAKE_ON_THE_RECORDS_OF_EMINENCE_OBJECTIVE_FROM                          = 12191,  -- Take on the % Records of Eminence objective from the Tutorial section of the Records of Eminence Menu and speak to the A.M.A.N. liaison.
